  const referralAccountPubKey = new PublicKey('AgentPubkeyPlaceholder11111111111111111111');

  const provider = new ReferralProvider(connection);

  const transactions = await provider.claimAllV2({
    payerPubKey: userPublicKey,
    referralAccountPubKey: referralAccountPubKey,
  });

  if (transactions.length === 0) {
    throw new Error('No claimable fees found for this referral account');
  }

  // Return the first claim transaction as base64
  const transaction = transactions[0];

  return Buffer.from(transaction.serialize()).toString('base64');
