```typescript
import {
  Connection,
  PublicKey,
  Keypair,
  VersionedTransaction,
  TransactionMessage,
} from '@solana/web3.js';
import {
  Liquidity,
  LiquidityPoolKeys,
  jsonInfo2PoolKeys,
  LiquidityPoolJsonInfo,
  TokenAccount,
  Token,
  TokenAmount,
  TOKEN_PROGRAM_ID,
  Percent,
  SPL_ACCOUNT_LAYOUT,
} from '@raydium-io/raydium-sdk';

const AGENT_PUBKEY = new PublicKey('AgentPubkeyPlaceholder11111111111111111111');
const RPC_URL = 'https://api.mainnet-beta.solana.com';
const TOKEN_A = 'So11111111111111111111111111111111111111112'; // SOL
const TOKEN_B = 'EPjFWdd5AufqSSqeM2qN1xzybapC8G4wEGGkZwyTDt1v'; // USDC
const SWAP_AMOUNT = 0.001;
const SLIPPAGE_PCT = 5;
const MAX_LAMPORTS = 1500000;

export async function executeSkill(blockhash: string): Promise<string> {
  const connection = new Connection(RPC_URL, { commitment: 'confirmed' });

  // Load pool keys from Raydium API
  const liquidityJsonResp = await fetch('https://api.raydium.io/v2/sdk/liquidity/mainnet.json');
  const liquidityJson = await liquidityJsonResp.json();
  const allPoolKeysJson: LiquidityPoolJsonInfo[] = [
    ...(liquidityJson?.official ?? []),
    ...(liquidityJson?.unOfficial ?? []),
  ];

  // Find pool for SOL/USDC pair
  const poolData = allPoolKeysJson.find(
    (i) =>
      (i.baseMint === TOKEN_A && i.quoteMint === TOKEN_B) ||
      (i.baseMint === TOKEN_B && i.quoteMint === TOKEN_A)
  );
  if (!poolData) throw new Error('Pool info not found for SOL/USDC pair');
  const poolKeys = jsonInfo2PoolKeys(poolData) as LiquidityPoolKeys;

  // Get token accounts owned by the agent
  const walletTokenAccount = await connection.getTokenAccountsByOwner(AGENT_PUBKEY, {
    programId: TOKEN_PROGRAM_ID,
  });
  const userTokenAccounts: TokenAccount[] = walletTokenAccount.value.map((i) => ({
    pubkey: i.pubkey,
    programId: i.account.owner,
    accountInfo: SPL_ACCOUNT_LAYOUT.decode(i.account.data),
  }));

  // Calculate swap amounts with slippage
  const poolInfo = await Liquidity.fetchInfo({ connection, poolKeys });
  const directionIn = poolKeys.quoteMint.toString() === TOKEN_B;
  let currencyInMint = poolKeys.baseMint;
  let currencyInDecimals = poolInfo.baseDecimals;
  let currencyOutMint = poolKeys.quoteMint;
  let currencyOutDecimals = poolInfo.quoteDecimals;
  if (!directionIn) {
    currencyInMint = poolKeys.quoteMint;
    currencyInDecimals = poolInfo.quoteDecimals;
    currencyOutMint = poolKeys.baseMint;
    currencyOutDecimals = poolInfo.baseDecimals;
  }
  const currencyIn = new Token(TOKEN_PROGRAM_ID, currencyInMint, currencyInDecimals);
  const amountIn = new TokenAmount(currencyIn, SWAP_AMOUNT, false);
  const currencyOut = new Token(TOKEN_PROGRAM_ID, currencyOutMint, currencyOutDecimals);
  const slippage = new Percent(SLIPPAGE_PCT, 100);
  const { minAmountOut } = Liquidity.computeAmountOut({
    poolKeys,
    poolInfo,
    amountIn,
    currencyOut,
    slippage,
  });

  // Build swap instructions
  const swapTransaction = await Liquidity.makeSwapInstructionSimple({
    connection,
    makeTxVersion: 0, // Versioned transaction
    poolKeys: { ...poolKeys },
    userKeys: {
      tokenAccounts: userTokenAccounts,
      owner: AGENT_PUBKEY,
    },
    amountIn,
    amountOut: minAmountOut,
    fixedSide: 'in',
    config: { bypassAssociatedCheck: false },
    computeBudgetConfig: { microLamports: MAX_LAMPORTS },
  });

  const instructions = swapTransaction.innerTransactions[0].instructions.filter(Boolean);

  // Build versioned transaction with provided blockhash
  const versionedTransaction = new VersionedTransaction(
    new TransactionMessage({
      payerKey: AGENT_PUBKEY,
      recentBlockhash: blockhash,
      instructions,
    }).compileToV0Message()
  );

  // Serialize and return as base64
  const serialized = versionedTransaction.serialize();
  return Buffer.from(serialized).toString('base64');
}
