  PublicKey,
  VersionedTransaction,
  TransactionMessage,
  TransactionInstruction,
} from '@solana/web3.js';
import {
  LiquidityPoolKeys,
  jsonInfo2PoolKeys,
  LiquidityPoolJsonInfo,
} from '@raydium-io/raydium-sdk';

const AGENT_PUBKEY = new PublicKey('AgentPubkeyPlaceholder11111111111111111111');
const RPC_URL = 'https://api.mainnet-beta.solana.com';
const TOKEN_A = 'So11111111111111111111111111111111111111112'; // SOL
const TOKEN_B = 'EPjFWdd5AufqSSqeM2qN1xzybapC8G4wEGGkZwyTDt1v'; // USDC

async function loadPoolKeys(liquidityUrl: string): Promise<LiquidityPoolJsonInfo[]> {
  const resp = await fetch(liquidityUrl);
  if (!resp.ok) throw new Error('Failed to fetch liquidity data');
  const liquidityJson = await resp.json();
  return [...(liquidityJson?.official ?? []), ...(liquidityJson?.unOfficial ?? [])];
}

function findPoolInfoForTokens(
  allPoolKeysJson: LiquidityPoolJsonInfo[],
  mintA: string,
  mintB: string
): LiquidityPoolKeys | null {
  const poolData = allPoolKeysJson.find(
    (i) =>
      (i.baseMint === mintA && i.quoteMint === mintB) ||
      (i.baseMint === mintB && i.quoteMint === mintA)
  );
  if (!poolData) return null;
  return jsonInfo2PoolKeys(poolData) as LiquidityPoolKeys;
}

export async function executeSkill(blockhash: string): Promise<string> {
  // Load all Raydium pool keys
  const allPoolKeysJson = await loadPoolKeys(
    'https://api.raydium.io/v2/sdk/liquidity/mainnet.json'
  );

  // Find pool for SOL/USDC
  const poolKeys = findPoolInfoForTokens(allPoolKeysJson, TOKEN_A, TOKEN_B);
  if (!poolKeys) throw new Error('No pool found for SOL/USDC pair');

  // Log pool info as a memo instruction to demonstrate the pattern
  const MEMO_PROGRAM_ID = new PublicKey('MemoSq4gqABAXKb96qnH8TysNcWxMyWCqXgDLGmfcHr');
  const memoData = Buffer.from(
    JSON.stringify({
      pool: poolKeys.id.toString(),
      baseMint: poolKeys.baseMint.toString(),
      quoteMint: poolKeys.quoteMint.toString(),
    })
  );
  const memoInstruction = new TransactionInstruction({
    keys: [{ pubkey: AGENT_PUBKEY, isSigner: true, isWritable: false }],
    programId: MEMO_PROGRAM_ID,
    data: memoData,
  });

  // Build versioned transaction
  const versionedTransaction = new VersionedTransaction(
    new TransactionMessage({
      payerKey: AGENT_PUBKEY,
      recentBlockhash: blockhash,
      instructions: [memoInstruction],
    }).compileToV0Message()
  );

  const serialized = versionedTransaction.serialize();
  return Buffer.from(serialized).toString('base64');
}
