```typescript
import {
  Connection,
  PublicKey,
  VersionedTransaction,
  TransactionMessage,
} from '@solana/web3.js';
import {
  Liquidity,
  LiquidityPoolKeys,
  jsonInfo2PoolKeys,
  LiquidityPoolJsonInfo,
  TokenAccount,
  Token,
  TokenAmount,
  TOKEN_PROGRAM_ID,
  Percent,
  SPL_ACCOUNT_LAYOUT,
} from '@raydium-io/raydium-sdk';

// === CONFIGURABLE PARAMETERS ===
const AGENT_PUBKEY = new PublicKey('AgentPubkeyPlaceholder11111111111111111111');
const RPC_URL = 'https://api.mainnet-beta.solana.com';
const LIQUIDITY_URL = 'https://api.raydium.io/v2/sdk/liquidity/mainnet.json';
const INPUT_MINT = 'So11111111111111111111111111111111111111112';  // SOL
const OUTPUT_MINT = 'EPjFWdd5AufqSSqeM2qN1xzybapC8G4wEGGkZwyTDt1v'; // USDC
const SWAP_AMOUNT_IN = 0.001;
const SLIPPAGE_BPS_NUMERATOR = 5;
const SLIPPAGE_BPS_DENOMINATOR = 100;
const PRIORITY_FEE_MICRO_LAMPORTS = 1500000;
const FIXED_SIDE: 'in' | 'out' = 'in';

export async function executeSkill(blockhash: string): Promise<string> {
  const connection = new Connection(RPC_URL, { commitment: 'confirmed' });

  // Step 1: Load all Raydium liquidity pool data
  const resp = await fetch(LIQUIDITY_URL);
  if (!resp.ok) throw new Error(`Failed to fetch liquidity data: ${resp.status}`);
  const liquidityJson = await resp.json();
  const allPoolKeysJson: LiquidityPoolJsonInfo[] = [
    ...(liquidityJson?.official ?? []),
    ...(liquidityJson?.unOfficial ?? []),
  ];

  // Step 2: Find pool for the configured token pair
  const poolData = allPoolKeysJson.find(
    (i) =>
      (i.baseMint === INPUT_MINT && i.quoteMint === OUTPUT_MINT) ||
      (i.baseMint === OUTPUT_MINT && i.quoteMint === INPUT_MINT)
  );
  if (!poolData) {
    throw new Error(`No Raydium pool found for ${INPUT_MINT} / ${OUTPUT_MINT}`);
  }
  const poolKeys = jsonInfo2PoolKeys(poolData) as LiquidityPoolKeys;

  // Step 3: Fetch on-chain pool state and wallet token accounts
  const [poolInfo, walletTokenAccountResp] = await Promise.all([
    Liquidity.fetchInfo({ connection, poolKeys }),
    connection.getTokenAccountsByOwner(AGENT_PUBKEY, { programId: TOKEN_PROGRAM_ID }),
  ]);

  const userTokenAccounts: TokenAccount[] = walletTokenAccountResp.value.map((i) => ({
    pubkey: i.pubkey,
    programId: i.account.owner,
    accountInfo: SPL_ACCOUNT_LAYOUT.decode(i.account.data),
  }));

  // Step 4: Compute swap output amounts with slippage
  const directionIn = poolKeys.quoteMint.toString() === OUTPUT_MINT;
  const currencyInMint = directionIn ? poolKeys.baseMint : poolKeys.quoteMint;
  const currencyInDecimals = directionIn ? poolInfo.baseDecimals : poolInfo.quoteDecimals;
  const currencyOutMint = directionIn ? poolKeys.quoteMint : poolKeys.baseMint;
  const currencyOutDecimals = directionIn ? poolInfo.quoteDecimals : poolInfo.baseDecimals;

  const currencyIn = new Token(TOKEN_PROGRAM_ID, currencyInMint, currencyInDecimals);
  const amountIn = new TokenAmount(currencyIn, SWAP_AMOUNT_IN, false);
  const currencyOut = new Token(TOKEN_PROGRAM_ID, currencyOutMint, currencyOutDecimals);
  const slippage = new Percent(SLIPPAGE_BPS_NUMERATOR, SLIPPAGE_BPS_DENOMINATOR);

  const { minAmountOut } = Liquidity.computeAmountOut({
    poolKeys,
    poolInfo,
    amountIn,
    currencyOut,
    slippage,
  });

  // Step 5: Generate swap instructions with compute budget priority fees
  const swapResult = await Liquidity.makeSwapInstructionSimple({
    connection,
    makeTxVersion: 0, // V0 versioned transaction
    poolKeys: { ...poolKeys },
    userKeys: {
      tokenAccounts: userTokenAccounts,
      owner: AGENT_PUBKEY,
    },
    amountIn,
    amountOut: minAmountOut,
    fixedSide: FIXED_SIDE,
    config: { bypassAssociatedCheck: false },
    computeBudgetConfig: { microLamports: PRIORITY_FEE_MICRO_LAMPORTS },
  });

  const instructions = swapResult.innerTransactions[0].instructions.filter(Boolean);

  // Step 6: Assemble versioned transaction
  const versionedTransaction = new VersionedTransaction(
    new TransactionMessage({
      payerKey: AGENT_PUBKEY,
      recentBlockhash: blockhash,
      instructions,
    }).compileToV0Message()
  );

  // Serialize and return as base64 (unsigned, ready for agent signing)
  const serialized = versionedTransaction.serialize();
  return Buffer.from(serialized).toString('base64');
}
