import { Connection, PublicKey, Transaction, SystemProgram } from "@solana/web3.js";
import { MathUtil, DecimalUtil } from "@orca-so/common-sdk";
import { AccountFetcher, PriceMath } from "@orca-so/whirlpools-sdk";
import { getAmountDeltaA, getAmountDeltaB } from "@orca-so/whirlpools-sdk/dist/utils/math/token-math";
import BN from "bn.js";
import Decimal from "decimal.js";

const AGENT_WALLET = new PublicKey("AgentPubkeyPlaceholder11111111111111111111");

function estLiquidityForTokenA(sqrtPrice1: BN, sqrtPrice2: BN, tokenAmount: BN): BN {
  const lowerSqrtPriceX64 = BN.min(sqrtPrice1, sqrtPrice2);
  const upperSqrtPriceX64 = BN.max(sqrtPrice1, sqrtPrice2);
  const num = MathUtil.fromX64_BN(tokenAmount.mul(upperSqrtPriceX64).mul(lowerSqrtPriceX64));
  const dem = upperSqrtPriceX64.sub(lowerSqrtPriceX64);
  return num.div(dem);
}

function estLiquidityForTokenB(sqrtPrice1: BN, sqrtPrice2: BN, tokenAmount: BN): BN {
  const lowerSqrtPriceX64 = BN.min(sqrtPrice1, sqrtPrice2);
  const upperSqrtPriceX64 = BN.max(sqrtPrice1, sqrtPrice2);
  const delta = upperSqrtPriceX64.sub(lowerSqrtPriceX64);
  return tokenAmount.shln(64).div(delta);
}

function getAmountAByAmountB(currentSqrtPrice: BN, lowerSqrtPrice: BN, upperSqrtPrice: BN, amountB: BN): BN | null {
  if (currentSqrtPrice.lte(lowerSqrtPrice)) return null;
  if (currentSqrtPrice.gte(upperSqrtPrice)) return new BN(0);
  const liquidity = estLiquidityForTokenB(lowerSqrtPrice, currentSqrtPrice, amountB);
  const amountA = getAmountDeltaA(currentSqrtPrice, upperSqrtPrice, liquidity, true);
  return amountA;
}

export async function executeSkill(blockhash: string): Promise<string> {
  const RPC_ENDPOINT_URL = "https://api.mainnet-beta.solana.com";
  const WHIRLPOOL_SOL_USDC_64 = new PublicKey("HJPjoWUrhoZzkNfRpHuieeFk9WcZWjwy6PBjZ81ngndJ");

  const connection = new Connection(RPC_ENDPOINT_URL);
  const fetcher = new AccountFetcher(connection);

  const whirlpool = await fetcher.getPool(WHIRLPOOL_SOL_USDC_64);
  const tokenA = await fetcher.getMintInfo(whirlpool.tokenMintA);
  const tokenB = await fetcher.getMintInfo(whirlpool.tokenMintB);

  const lowerPrice = new Decimal(20);
  const upperPrice = new Decimal(40);
  const amountB = DecimalUtil.toU64(new Decimal(100), tokenB.decimals);

  const lowerIndex = PriceMath.priceToInitializableTickIndex(lowerPrice, tokenA.decimals, tokenB.decimals, whirlpool.tickSpacing);
  const upperIndex = PriceMath.priceToInitializableTickIndex(upperPrice, tokenA.decimals, tokenB.decimals, whirlpool.tickSpacing);
  const lowerSqrtPrice = PriceMath.tickIndexToSqrtPriceX64(lowerIndex);
