  TICK_ARRAY_SIZE, MIN_TICK_INDEX, MAX_TICK_INDEX, PriceMath, TickArray
} from "@orca-so/whirlpools-sdk";
import Decimal from "decimal.js";

const AGENT_WALLET = new PublicKey("AgentPubkeyPlaceholder11111111111111111111");

function getSqrtPriceSafeLimit(tickarrays: TickArray[], aToB: boolean, tickSpacing: number): BN {
  const lastTickarray = tickarrays[2] ?? tickarrays[1] ?? tickarrays[0];
  const lastTickIndex = aToB
    ? lastTickarray.data.startTickIndex
    : lastTickarray.data.startTickIndex + tickSpacing * (TICK_ARRAY_SIZE - 1);
  const boundLastTickIndex = Math.min(MAX_TICK_INDEX, Math.max(MIN_TICK_INDEX, lastTickIndex));
  return PriceMath.tickIndexToSqrtPriceX64(boundLastTickIndex);
}

