import { Buffer } from "buffer";
import { Connection, PublicKey, Transaction, SystemProgram, TransactionInstruction, CompiledInstruction } from "@solana/web3.js";
import { ORCA_WHIRLPOOL_PROGRAM_ID } from "@orca-so/whirlpools-sdk";
import { BorshCoder, Idl } from "@coral-xyz/anchor";
import { DecodedTransferInstruction, TOKEN_PROGRAM_ID, decodeTransferInstruction } from "@solana/spl-token";
import bs58 from "bs58";
import whirlpoolIdl from "@orca-so/whirlpools-sdk/dist/artifacts/whirlpool.json";

const AGENT_WALLET = new PublicKey("AgentPubkeyPlaceholder11111111111111111111");

function decodeTokenInstruction(ix: CompiledInstruction, accounts: PublicKey[]): DecodedTransferInstruction {
  const data = Buffer.from(bs58.decode(ix.data));
  return decodeTransferInstruction(new TransactionInstruction({
    programId: TOKEN_PROGRAM_ID,
    data,
    keys: [
      { pubkey: accounts[ix.accounts[0]], isSigner: false, isWritable: true },
      { pubkey: accounts[ix.accounts[1]], isSigner: false, isWritable: true },
      { pubkey: accounts[ix.accounts[2]], isSigner: true, isWritable: true },
    ]
  }));
}

export async function executeSkill(blockhash: string): Promise<string> {
  const RPC_ENDPOINT_URL = "https://api.mainnet-beta.solana.com";
  const connection = new Connection(RPC_ENDPOINT_URL, "confirmed");

  const signature = "57QKWfyNgv4dHmL97r18fkb7GZQsGQCuRRVkWTofGB1Z8sz5NB3gJ52Tzy4d4Wzwb4x2G3Krirsu33nTeSSB46Sp";
  const tx = await connection.getTransaction(signature, { commitment: "confirmed", maxSupportedTransactionVersion: 0 });

  const txmsg = tx!.transaction.message;
  const instructions = txmsg.compiledInstructions;
  const staticKeys = txmsg.staticAccountKeys;
  const writableKeys = tx!.meta!.loadedAddresses!.writable;
  const readonlyKeys = tx!.meta!.loadedAddresses!.readonly;
  const accounts: PublicKey[] = [...staticKeys, ...writableKeys, ...readonlyKeys];
  const innerInstructions = tx!.meta!.innerInstructions || [];

  const allInstructions: CompiledInstruction[] = [];
  instructions.forEach((ix, i) => {
    allInstructions.push({ programIdIndex: ix.programIdIndex, data: bs58.encode(ix.data), accounts: ix.accountKeyIndexes as number[] });
    const inner = innerInstructions.find((v) => v.index === i);
    inner?.instructions.forEach((innerIx) => allInstructions.push(innerIx));
  });

  const coder = new BorshCoder(whirlpoolIdl as Idl);

  for (let cursor = 0; cursor < allInstructions.length; cursor++) {
    const ix = allInstructions[cursor];
    const programId = accounts[ix.programIdIndex];
    if (!programId.equals(ORCA_WHIRLPOOL_PROGRAM_ID)) continue;

    const decoded = coder.instruction.decode(ix.data, "base58");
    console.log("whirlpool instruction:", decoded!.name);

    switch (decoded!.name) {
      case "twoHopSwap": {
        for (let j = 1; j <= 4; j++) {
          const transferIx = decodeTokenInstruction(allInstructions[cursor + j], accounts);
          console.log(`  transfer: ${transferIx.keys.source.pubkey.toBase58()} >> ${transferIx.keys.destination.pubkey.toBase58()} ${transferIx.data.amount.toString()}`);
        }
        break;
      }
      case "swap":
      case "increaseLiquidity":
      case "decreaseLiquidity":
      case "collectFees":
      case "collectProtocolFees": {
        for (let j = 1; j <= 2; j++) {
          const transferIx = decodeTokenInstruction(allInstructions[cursor + j], accounts);
          console.log(`  transfer: ${transferIx.keys.source.pubkey.toBase58()} >> ${transferIx.keys.destination.pubkey.toBase58()} ${transferIx.data.amount.toString()}`);
        }
        break;
      }
      case "collectReward": {
        const transferIx = decodeTokenInstruction(allInstructions[cursor + 1], accounts);
        console.log(`  transfer: ${transferIx.keys.source.pubkey.toBase58()} >> ${transferIx.keys.destination.pubkey.toBase58()} ${transferIx.data.amount.toString()}`);
        break;
      }
    }
  }

  const resultTx = new Transaction();
  resultTx.recentBlockhash = blockhash;
  resultTx.feePayer = AGENT_WALLET;
  resultTx.add(SystemProgram.transfer({ fromPubkey: AGENT_WALLET, toPubkey: AGENT_WALLET, lamports: 0 }));
  return Buffer.from(resultTx.serialize({ requireAllSignatures: false })).toString("base64");
}
