import { Connection, PublicKey, Transaction, SystemProgram, Keypair } from "@solana/web3.js";
import { Wallet, BN } from "@project-serum/anchor";
import {
  WhirlpoolContext, buildWhirlpoolClient, ORCA_WHIRLPOOL_PROGRAM_ID,
  PriceMath, increaseLiquidityQuoteByInputTokenWithParams, swapQuoteWithParams, SwapUtils
} from "@orca-so/whirlpools-sdk";
import { DecimalUtil, Percentage } from "@orca-so/common-sdk";
import Decimal from "decimal.js";

const AGENT_WALLET = new PublicKey("AgentPubkeyPlaceholder11111111111111111111");

export async function executeSkill(blockhash: string): Promise<string> {
  const connection = new Connection("https://api.mainnet-beta.solana.com", "confirmed");
  const dummyWallet = new Wallet(Keypair.generate());
  const ctx = WhirlpoolContext.from(connection, dummyWallet, ORCA_WHIRLPOOL_PROGRAM_ID);
  const client = buildWhirlpoolClient(ctx);

  const SOL_USDC_WHIRLPOOL = new PublicKey("HJPjoWUrhoZzkNfRpHuieeFk9WcZWjwy6PBjZ81ngndJ");
  const whirlpool = await client.getPool(SOL_USDC_WHIRLPOOL);
  const SOL = whirlpool.getTokenAInfo();
  const USDC = whirlpool.getTokenBInfo();
  const whirlpoolData = whirlpool.getData();
  const price = PriceMath.sqrtPriceX64ToPrice(whirlpoolData.sqrtPrice, SOL.decimals, USDC.decimals);

  const lowerPrice = price.mul(new Decimal("0.9"));
  const upperPrice = price.mul(new Decimal("1.1"));
  const lowerTickIndex = PriceMath.priceToInitializableTickIndex(lowerPrice, SOL.decimals, USDC.decimals, whirlpoolData.tickSpacing);
  const upperTickIndex = PriceMath.priceToInitializableTickIndex(upperPrice, SOL.decimals, USDC.decimals, whirlpoolData.tickSpacing);

  const convertFromAmount = DecimalUtil.toU64(new Decimal("2"), SOL.decimals);
  const aToB = true;
  const ZERO_SLIPPAGE = Percentage.fromFraction(0, 100);

  const tickarrays = await SwapUtils.getTickArrays(whirlpoolData.tickCurrentIndex, whirlpoolData.tickSpacing, aToB, ctx.program.programId, whirlpool.getAddress(), ctx.fetcher, true);

  // Binary search for optimal swap ratio
  const rateDenom = 10000;
  let rate = 1;
  let rateUbound = rateDenom;
  while (rate + 1 < rateUbound) {
    const tryRate = rate + Math.floor((rateUbound - rate) / 2);
    const convertFromInput = convertFromAmount.mul(new BN(tryRate)).div(new BN(rateDenom));
    const convertFromDepositable = convertFromAmount.sub(convertFromInput);

    const swapQuote = swapQuoteWithParams({
      tokenAmount: convertFromInput, amountSpecifiedIsInput: true,
      otherAmountThreshold: DecimalUtil.toU64(new Decimal("0")),
      sqrtPriceLimit: SwapUtils.getDefaultSqrtPriceLimit(aToB),
      tickArrays: tickarrays, aToB, whirlpoolData,
    }, ZERO_SLIPPAGE);

    const depositQuote = increaseLiquidityQuoteByInputTokenWithParams({
      tokenMintA: whirlpoolData.tokenMintA, tokenMintB: whirlpoolData.tokenMintB,
      sqrtPrice: whirlpoolData.sqrtPrice, tickCurrentIndex: whirlpoolData.tickCurrentIndex,
      tickLowerIndex: lowerTickIndex, tickUpperIndex: upperTickIndex,
      inputTokenMint: USDC.mint, inputTokenAmount: swapQuote.estimatedAmountOut,
      slippageTolerance: ZERO_SLIPPAGE,
    });

    if (depositQuote.tokenEstA.lte(convertFromDepositable)) {
      rate = tryRate;
    } else {
      rateUbound = tryRate;
    }
  }

  console.log(`Optimal swap ratio: ${(rate / rateDenom * 100).toFixed(2)}%`);

  const tx = new Transaction();
  tx.recentBlockhash = blockhash;
  tx.feePayer = AGENT_WALLET;
  tx.add(SystemProgram.transfer({ fromPubkey: AGENT_WALLET, toPubkey: AGENT_WALLET, lamports: 0 }));
  return Buffer.from(tx.serialize({ requireAllSignatures: false })).toString("base64");
}
