  const tickSpacing = whirlpool.getData().tickSpacing;

  const tickArrayLowerPubkey = PDAUtil.getTickArrayFromTickIndex(position.getData().tickLowerIndex, tickSpacing, whirlpoolPubkey, ctx.program.programId).publicKey;
