  const provider = new AnchorProvider(connection, wallet, { commitment: 'confirmed' });
  const ctx = WhirlpoolContext.withProvider(provider, ORCA_WHIRLPOOL_PROGRAM_ID);
  const client = buildWhirlpoolClient(ctx);

  // Sort mints to determine token A and token B (lower pubkey = token A)
  const [tokenMintA, tokenMintB] = PoolUtil.orderMints(MYTOKEN_MINT, USDC_MINT);
  const mintAPubkey = new PublicKey(tokenMintA);
  const mintBPubkey = new PublicKey(tokenMintB);

  // Calculate initial sqrt price from price $1.50
  // Price = tokenB / tokenA (USDC per MYTOKEN)
  const initialPrice = new Decimal('1.50');
  const decA = mintAPubkey.equals(MYTOKEN_MINT) ? MYTOKEN_DECIMALS : USDC_DECIMALS;
  const decB = mintBPubkey.equals(USDC_MINT) ? USDC_DECIMALS : MYTOKEN_DECIMALS;
  const initSqrtPrice = PriceMath.priceToSqrtPriceX64(initialPrice, decA, decB);

  // Derive the Whirlpool PDA
  const whirlpoolPda = PDAUtil.getWhirlpool(
    ORCA_WHIRLPOOL_PROGRAM_ID,
    ORCA_WHIRLPOOLS_CONFIG,
    mintAPubkey,
    mintBPubkey,
    TICK_SPACING
  );

  // Derive fee tier PDA
  const feeTierPda = PDAUtil.getFeeTier(
    ORCA_WHIRLPOOL_PROGRAM_ID,
    ORCA_WHIRLPOOLS_CONFIG,
    TICK_SPACING
  );

  // Derive token vault keypairs
  const tokenVaultAKeypair = Keypair.generate();
  const tokenVaultBKeypair = Keypair.generate();

  const initPoolIx = WhirlpoolIx.initializePoolIx(ctx.program, {
    whirlpoolsConfig: ORCA_WHIRLPOOLS_CONFIG,
    whirlpoolPda,
    tokenMintA: mintAPubkey,
    tokenMintB: mintBPubkey,
    tokenVaultAKeypair,
    tokenVaultBKeypair,
    feeTierKey: feeTierPda.publicKey,
    tickSpacing: TICK_SPACING,
    funder: AGENT_WALLET,
    initSqrtPrice,
  });

  const transaction = new Transaction();
  transaction.add(initPoolIx);
  transaction.recentBlockhash = blockhash;
  transaction.feePayer = AGENT_WALLET;

  // Partial sign with vault keypairs
  transaction.partialSign(tokenVaultAKeypair, tokenVaultBKeypair);

  return Buffer.from(transaction.serialize({ requireAllSignatures: false })).toString('base64');
}
