import axios from 'axios';
import Decimal from 'decimal.js';

export async function executeSkill(blockhash: string): Promise<string> {
  const OWNER_PUBKEY = new PublicKey('11111111111111111111111111111111');
  const connection = new Connection('https://api.mainnet-beta.solana.com', 'confirmed');

  const raydium = await Raydium.load({
    connection,
    owner: OWNER_PUBKEY,
    cluster: 'mainnet',
    disableFeatureCheck: true,
    disableLoadToken: true,
    blockhashCommitment: 'finalized',
  });

  // Fetch all CPMM pools where the wallet has pending creator fees
  const host = 'https://temp-api-v1.raydium.io';
  const cpmmCreatorFeeRes: {
    id: string;
    success: boolean;
    data: {
      fee: { amountA: string; amountB: string };
      poolInfo: ApiV3PoolInfoStandardItemCpmm;
      poolKey: CpmmKeys;
    }[];
  } = (await axios.get(`${host}/cp-creator-fee?wallet=${raydium.ownerPubKey.toBase58()}`)).data;

  if (!cpmmCreatorFeeRes.data.length) {
    throw new Error('wallet does not have any CPMM creator fees to collect');
  }

  // Filter pools that have non-zero fees
  const poolsWithFees = cpmmCreatorFeeRes.data.filter(
    (d) => d.fee.amountA !== '0' || d.fee.amountB !== '0'
  );

  if (poolsWithFees.length === 0) {
    throw new Error('no pending creator fees across any pools');
  }

  // Build batch collect transactions
  const { execute, transactions } = await raydium.cpmm.collectMultiCreatorFees({
    poolInfoList: poolsWithFees.map((d) => d.poolInfo),
    programId: CREATE_CPMM_POOL_PROGRAM,
    txVersion: TxVersion.V0,
  });

  // Serialize the first transaction (or all if needed)
  const firstTx = transactions[0];
  const serializedTx = firstTx instanceof VersionedTransaction
    ? Buffer.from(firstTx.serialize()).toString('base64')
    : Buffer.from(firstTx.serialize()).toString('base64');

  return serializedTx;
}
