import { TOKEN_PROGRAM_ID, TOKEN_2022_PROGRAM_ID } from '@solana/spl-token';

export async function executeSkill(blockhash: string): Promise<string> {
  const OWNER_PUBKEY = new PublicKey('11111111111111111111111111111111');
  const connection = new Connection('https://api.mainnet-beta.solana.com', 'confirmed');

  // Initialize Raydium SDK - singleton pattern
  const raydium = await Raydium.load({
    connection,
    owner: OWNER_PUBKEY,
    cluster: 'mainnet',
    disableFeatureCheck: true,
    disableLoadToken: true,
    blockhashCommitment: 'finalized',
  });

  // Optionally fetch and set token accounts manually
  const solAccountResp = await connection.getAccountInfo(OWNER_PUBKEY);
  const tokenAccountResp = await connection.getTokenAccountsByOwner(OWNER_PUBKEY, {
    programId: TOKEN_PROGRAM_ID,
  });
  const token2022Resp = await connection.getTokenAccountsByOwner(OWNER_PUBKEY, {
    programId: TOKEN_2022_PROGRAM_ID,
  });

  const tokenAccountData = parseTokenAccountResp({
    owner: OWNER_PUBKEY,
    solAccountResp,
    tokenAccountResp: {
      context: tokenAccountResp.context,
      value: [...tokenAccountResp.value, ...token2022Resp.value],
    },
  });

  // After calling updateTokenAccount, SDK won't auto-fetch token accounts
  raydium.account.updateTokenAccount(tokenAccountData);

  return JSON.stringify({
    initialized: true,
    cluster: 'mainnet',
    owner: OWNER_PUBKEY.toBase58(),
    tokenAccountCount: tokenAccountData.tokenAccounts?.length ?? 0,
  });
}
