export async function executeSkill(blockhash: string): Promise<string> {
  const inputToken = new Token(TOKEN_PROGRAM_ID, new PublicKey('EPjFWdd5AufqSSqeM2qN1xzybapC8G4wEGGkZwyTDt1v'), 6, 'USDC', 'USDC');
  const outputToken = new Token(TOKEN_PROGRAM_ID, new PublicKey('4k3Dyjzvzp8eMZWUXbBCjEvwSkkk59S5iCNLY3QrkX6R'), 6, 'RAY', 'RAY');
  const targetPool = 'CLMM_POOL_ID_HERE';
  const inputTokenAmount = new TokenAmount(inputToken, 100);
  const slippage = new Percent(1, 100);
  const walletTokenAccounts = await getWalletTokenAccount(connection, PLACEHOLDER_WALLET.publicKey);

  // Step 1: fetch CLMM pool info
  const clmmPoolKey: ApiClmmPoolsItem = {} as any; // fetched from API or on-chain
  const clmmPools: ApiClmmPoolsItem[] = [clmmPoolKey];
  const { [targetPool]: clmmPoolInfo } = await Clmm.fetchMultiplePoolInfos({
    connection,
    poolKeys: clmmPools,
    chainTime: new Date().getTime() / 1000,
  });

  // Step 2: fetch tick arrays
  const tickCache = await Clmm.fetchMultiplePoolTickArrays({
    connection,
    poolKeys: [clmmPoolInfo.state],
    batchRequest: true,
  });

  // Step 3: compute amount out
  const { minAmountOut, remainingAccounts } = Clmm.computeAmountOutFormat({
    poolInfo: clmmPoolInfo.state,
    tickArrayCache: tickCache[targetPool],
    amountIn: inputTokenAmount,
    currencyOut: outputToken,
    slippage,
    epochInfo: await connection.getEpochInfo(),
    token2022Infos: await fetchMultipleMintInfos({
      connection,
      mints: clmmPools
        .map(i => [{ mint: i.mintA, program: i.mintProgramIdA }, { mint: i.mintB, program: i.mintProgramIdB }])
        .flat()
        .filter(i => i.program === TOKEN_2022_PROGRAM_ID.toString())
        .map(i => new PublicKey(i.mint)),
    }),
    catchLiquidityInsufficient: false,
  });

  // Step 4: build swap instruction
  const { innerTransactions } = await Clmm.makeSwapBaseInInstructionSimple({
    connection,
    poolInfo: clmmPoolInfo.state,
    ownerInfo: {
      feePayer: PLACEHOLDER_WALLET.publicKey,
      wallet: PLACEHOLDER_WALLET.publicKey,
      tokenAccounts: walletTokenAccounts,
    },
    inputMint: inputTokenAmount.token.mint,
    amountIn: inputTokenAmount.raw,
    amountOutMin: minAmountOut.amount.raw,
    remainingAccounts,
    makeTxVersion: TxVersion.V0,
  });

  // Step 5: serialize
  const willSendTx = await buildSimpleTransaction({
    connection,
    makeTxVersion: TxVersion.V0,
    payer: PLACEHOLDER_WALLET.publicKey,
    innerTransactions,
  });

  const tx = willSendTx[0];
  if (tx instanceof VersionedTransaction) {
    tx.message.recentBlockhash = blockhash;
    return Buffer.from(tx.serialize()).toString('base64');
  }
  tx.recentBlockhash = blockhash;
  return Buffer.from(tx.serialize({ verifySignatures: false })).toString('base64');
}
