  const endPrice = new Decimal(1);
  const slippage = 0.01;
  const walletTokenAccounts = await getWalletTokenAccount(connection, PLACEHOLDER_WALLET.publicKey);

  if (startPrice.gte(endPrice)) throw Error('price input error');

