      tokenAccounts: walletTokenAccounts,
    },
  });

  // Step 2: get tick bounds from price range
  const { tick: tickLower } = Clmm.getPriceAndTick({ poolInfo, baseIn: true, price: startPrice });
  const { tick: tickUpper } = Clmm.getPriceAndTick({ poolInfo, baseIn: true, price: endPrice });

  // Step 3: compute liquidity from input amount
  const { liquidity, amountSlippageA, amountSlippageB } = Clmm.getLiquidityAmountOutFromAmountIn({
    poolInfo,
    slippage,
    inputA: inputTokenMint === 'mintA',
    tickUpper,
    tickLower,
    amount: new BN(inputTokenAmount.mul(10 ** poolInfo[inputTokenMint].decimals).toFixed(0)),
    add: true,
    amountHasFee: true,
    token2022Infos: await fetchMultipleMintInfos({ connection, mints: [poolInfo.mintA.mint, poolInfo.mintB.mint] }),
    epochInfo: await connection.getEpochInfo(),
  });

  // Step 4: build open position instruction
  const makeOpenPositionInstruction = await Clmm.makeOpenPositionFromLiquidityInstructionSimple({
    connection,
    poolInfo,
    ownerInfo: {
      feePayer: PLACEHOLDER_WALLET.publicKey,
      wallet: PLACEHOLDER_WALLET.publicKey,
      tokenAccounts: walletTokenAccounts,
    },
    tickLower,
    tickUpper,
    liquidity,
    makeTxVersion: TxVersion.V0,
    amountMaxA: amountSlippageA.amount,
    amountMaxB: amountSlippageB.amount,
  });

  const willSendTx = await buildSimpleTransaction({
    connection,
    makeTxVersion: TxVersion.V0,
    payer: PLACEHOLDER_WALLET.publicKey,
