  const targetPool = 'CLMM_POOL_ID_HERE';
  const inputTokenAmount = new Decimal(1);
  const inputTokenMint: 'mintA' | 'mintB' = 'mintA';
  const positionMint = new PublicKey('POSITION_NFT_MINT_HERE');
  const walletTokenAccounts = await getWalletTokenAccount(connection, PLACEHOLDER_WALLET.publicKey);

