import { Connection, PublicKey, Transaction, VersionedTransaction } from '@solana/web3.js';
import { NATIVE_MINT } from '@solana/spl-token';
import axios from 'axios';
import { API_URLS } from '@raydium-io/raydium-sdk-v2';

async function tryJupiterLegacySwap(
  agent: PublicKey,
  blockhash: string,
  inputMint: string,
  outputMint: string,
  amount: number,
  slippageBps: number
): Promise<string | null> {
  // 1) Quote
  const quoteUrl = 'https://quote-api.jup.ag/v6/quote?' + new URLSearchParams({
    inputMint,
    outputMint,
    amount: String(amount),
    slippageBps: String(slippageBps),
  });
  const quoteRes = await fetch(quoteUrl);
  if (!quoteRes.ok) return null;
  const quote = await quoteRes.json();
  if (!quote || quote.error) return null;

  // 2) Build legacy transaction (avoid address lookup tables)
  const swapRes = await fetch('https://quote-api.jup.ag/v6/swap', {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({
      quoteResponse: quote,
      userPublicKey: agent.toBase58(),
      wrapAndUnwrapSol: true,
      // Keep it simple for sandbox: no dynamic CU, no priority fees, no shared accounts
      asLegacyTransaction: true,
      dynamicComputeUnitLimit: false,
      useSharedAccounts: false,
    }),
  });
  if (!swapRes.ok) return null;
  const swapData = await swapRes.json();
  const txB64: string | undefined = swapData?.swapTransaction;
  if (!txB64) return null;

  // 3) Patch blockhash and return
  const buf = Buffer.from(txB64, 'base64');
  try {
    const legacy = Transaction.from(buf);
    legacy.recentBlockhash = blockhash;
    legacy.feePayer = agent;
    return legacy.serialize({ requireAllSignatures: false }).toString('base64');
  } catch {
    // In rare cases Jupiter might still return v0; handle just in case
    try {
      const vtx = VersionedTransaction.deserialize(buf);
      vtx.message.recentBlockhash = blockhash;
      return Buffer.from(vtx.serialize()).toString('base64');
    } catch {
      return null;
    }
  }
}

async function tryRaydiumLegacySwap(
  agent: PublicKey,
  blockhash: string,
  inputMint: string,
  outputMint: string,
  amount: number,
  slippageBps: number
): Promise<string | null> {
  // 1) Fetch priority fee (optional)
  let cuPrice = '0';
  try {
    const { data: feeData } = await axios.get<{ success: boolean; data: { default: { vh: number; h: number; m: number } } }>(
      `${API_URLS.BASE_HOST}${API_URLS.PRIORITY_FEE}`
    );
    cuPrice = String(feeData?.data?.default?.m ?? 0);
  } catch {
    // ignore, keep 0
  }

  const txVersion = 'LEGACY';

  // 2) Quote
  const { data: quote } = await axios.get<any>(
    `${API_URLS.SWAP_HOST}/compute/swap-base-in?` +
      `inputMint=${inputMint}&outputMint=${outputMint}&amount=${amount}&slippageBps=${slippageBps}&txVersion=${txVersion}`
  );
  if (!quote?.success) return null;

  // 3) Transaction (legacy)
  const { data: swapResp } = await axios.post<{
    success: boolean;
    data?: { transaction: string }[];
  }>(`${API_URLS.SWAP_HOST}/transaction/swap-base-in`, {
    computeUnitPriceMicroLamports: cuPrice,
    swapResponse: quote,
    txVersion,
    wallet: agent.toBase58(),
    wrapSol: true,
    unwrapSol: false,
    inputAccount: undefined,
    outputAccount: undefined,
  });

  const txB64 = swapResp?.data?.[0]?.transaction;
  if (!swapResp?.success || !txB64) return null;

  // 4) Patch blockhash and return
  try {
    const legacy = Transaction.from(Buffer.from(txB64, 'base64'));
    legacy.recentBlockhash = blockhash;
    legacy.feePayer = agent;
    return legacy.serialize({ requireAllSignatures: false }).toString('base64');
  } catch {
    return null;
  }
}

