        wrapAndUnwrapSol: true,
        dynamicComputeUnitLimit: true,
        prioritizationFeeLamports: 'auto',
      }),
    });
    const swapData = await swapRes.json();

    if (!swapData || !swapData.swapTransaction) {
      throw new Error(`Jupiter swap build failed: ${JSON.stringify(swapData)}`);
    }

    return serializeWithBlockhash(swapData.swapTransaction);
  } catch (e) {
    // Fall through to Raydium if Jupiter path fails
    // console.warn('Jupiter path failed, trying Raydium...', e);
  }

  // 2) Raydium: request LEGACY tx as well
  try {
    const inputMint = NATIVE_MINT.toBase58(); // SOL
