    try {
      const { data: feeData } = await axios.get<{
        id: string;
        success: boolean;
        data: { default: { vh: number; h: number; m: number } };
      }>(`${API_URLS.BASE_HOST}${API_URLS.PRIORITY_FEE}`);
      computeUnitPriceMicroLamports = String(feeData?.data?.default?.h ?? 15000);
    } catch {}

    // Quote
    const { data: swapResponse } = await axios.get<any>(
      `${API_URLS.SWAP_HOST}/compute/swap-base-in?` +
        `inputMint=${inputMint}&outputMint=${outputMint}&amount=${amountLamports}&` +
        `slippageBps=${slippageBps}&txVersion=${txVersion}`
    );

    if (!swapResponse?.success) {
      throw new Error(`Raydium quote failed: ${JSON.stringify(swapResponse)}`);
    }

    // Build transaction (legacy)
    const { data: swapTxResp } = await axios.post<{
      id: string;
      version: string;
      success: boolean;
      data: { transaction: string }[];
    }>(`${API_URLS.SWAP_HOST}/transaction/swap-base-in`, {
      computeUnitPriceMicroLamports,
      swapResponse,
      txVersion,
      wallet: agentPubkey.toBase58(),
      wrapSol: true,
      unwrapSol: false,
      inputAccount: undefined,
      outputAccount: undefined,
    });

    if (!swapTxResp?.data?.length || !swapTxResp.data[0]?.transaction) {
      throw new Error(`Raydium transaction not returned: ${JSON.stringify(swapTxResp)}`);
    }

    return serializeWithBlockhash(swapTxResp.data[0].transaction);
  } catch (e2) {
    throw new Error(`All swap attempts failed. Last error: ${String(e2)}`);
  }
}
