        const feeData = feeResponse.data;

        // Step 2: Get swap quote
        const quoteResponse = await axios.get(
            `https://api.raydium.io/v2/ammV3/swap/compute/swap-base-in?` +
            `inputMint=${inputMint}&outputMint=${outputMint}&amount=${amount}&` +
            `slippageBps=${slippage * 100}&txVersion=${txVersion}`
        );

        if (!quoteResponse.data.success) {
            throw new Error('Raydium quote failed');
        }

        // Step 3: Get swap transaction
        const swapResponse = await axios.post('https://api.raydium.io/v2/ammV3/swap/transaction/swap-base-in', {
            computeUnitPriceMicroLamports: String(feeData.data?.default?.h || 1000),
            swapResponse: quoteResponse.data,
            txVersion,
            wallet: agentPubkey.toBase58(),
            wrapSol: true,
            unwrapSol: false,
        });

        if (!swapResponse.data.data || swapResponse.data.data.length === 0) {
            throw new Error('No transaction returned from Raydium');
        }

        // Process the transaction
        const txBuf = Buffer.from(swapResponse.data.data[0].transaction, 'base64');
        const transaction = VersionedTransaction.deserialize(txBuf);

        // Update blockhash
        transaction.message.recentBlockhash = blockhash;

        return Buffer.from(transaction.serialize()).toString('base64');

