import { Connection, PublicKey, Transaction } from '@solana/web3.js';
import { NATIVE_MINT } from '@solana/spl-token';
import axios from 'axios';
import { API_URLS } from '@raydium-io/raydium-sdk-v2';

const ROUTER = 'routeUGWgWzqBWFcrCfv8tritsqukccJPu3q5GPP3xS';
const RAYDIUM_CLMM = 'CAMMCzo5YL8w4VFF8KVHrK22GGUsp5VTaW7grrKgrWqK';
const TOKEN_PROGRAM = 'TokenkegQfeZyiNwAJbNbGKPFXCWuBvf9Ss623VQ5DA';
const ATA_PROGRAM = 'ATokenGPvbdGVxr1b2hvZbsiqW5xWH25efTNsLJA8knL';
const SYSTEM_PROGRAM = '11111111111111111111111111111111';

function containsRaydiumSwap(tx: Transaction): boolean {
  return tx.instructions.some(ix => {
    const pid = ix.programId.toBase58();
    return pid === ROUTER || pid === RAYDIUM_CLMM;
  });
}

function isSetupOnly(tx: Transaction): boolean {
  // Heuristic: only System, ATA, Token program instructions -> setup/close only
  return tx.instructions.every(ix => {
    const pid = ix.programId.toBase58();
    return pid === SYSTEM_PROGRAM || pid === ATA_PROGRAM || pid === TOKEN_PROGRAM;
  });
}

async function buildRaydiumBaseInLegacyTxBase64(
  agent: PublicKey,
  inputMint: string,
  outputMint: string,
  amountIn: number,
  slippageBps: number
): Promise<string | null> {
  const txVersion = 'LEGACY';

  // 1) Compute quote
  const { data: quote } = await axios.get<any>(
    `${API_URLS.SWAP_HOST}/compute/swap-base-in?` +
      `inputMint=${inputMint}&outputMint=${outputMint}&amount=${amountIn}&slippageBps=${slippageBps}&txVersion=${txVersion}`
  );
  if (!quote?.success) return null;

  // 2) Build transactions
  const { data: txResp } = await axios.post<{
    success: boolean;
    data?: { transaction: string }[];
  }>(`${API_URLS.SWAP_HOST}/transaction/swap-base-in`, {
    computeUnitPriceMicroLamports: '0',
    swapResponse: quote,
    txVersion,
    wallet: agent.toBase58(),
    wrapSol: true,
    unwrapSol: false,
    inputAccount: undefined,
    outputAccount: undefined,
  });

  if (!txResp?.success || !txResp.data || txResp.data.length === 0) return null;

  // 3) Prefer the tx that contains the router/amm swap (not only setup/close)
  for (const { transaction } of txResp.data) {
    try {
      const legacy = Transaction.from(Buffer.from(transaction, 'base64'));
      if (containsRaydiumSwap(legacy) && !isSetupOnly(legacy)) {
        return transaction;
      }
    } catch {
      // skip
    }
  }
  // If none matched, fallback to last tx (often the swap). Guard with containsRaydiumSwap.
  const last = txResp.data[txResp.data.length - 1]?.transaction;
  if (last) {
    try {
      const legacy = Transaction.from(Buffer.from(last, 'base64'));
      if (containsRaydiumSwap(legacy)) return last;
    } catch {}
  }
  return null;
}

async function buildJupLegacySwapTxBase64(
  agent: PublicKey,
  inputMint: string,
  outputMint: string,
  amount: number,
  slippageBps: number,
  preferDexes?: string[],
  onlyDirectRoutes?: boolean
): Promise<string | null> {
  const qs = new URLSearchParams({
    inputMint,
    outputMint,
    amount: String(amount),
    slippageBps: String(slippageBps),
    swapMode: 'ExactIn',
  });
  if (preferDexes && preferDexes.length) qs.set('preferDexes', preferDexes.join(','));
  if (onlyDirectRoutes !== undefined) qs.set('onlyDirectRoutes', String(!!onlyDirectRoutes));

  const quoteRes = await fetch(`https://quote-api.jup.ag/v6/quote?${qs.toString()}`);
  if (!quoteRes.ok) return null;
  const quote = await quoteRes.json();
  if (!quote || quote.error) return null;

  const swapRes = await fetch('https://quote-api.jup.ag/v6/swap', {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({
      quoteResponse: quote,
      userPublicKey: agent.toBase58(),
      wrapAndUnwrapSol: true,
      asLegacyTransaction: true,
      dynamicComputeUnitLimit: false,
      useSharedAccounts: false,
    }),
  });
  if (!swapRes.ok) return null;
  const swapData = await swapRes.json();
  return swapData?.swapTransaction ?? null;
}

