import {
  VersionedTransaction,
  TransactionMessage,
  TransactionInstruction,
  PublicKey,
  AddressLookupTableAccount,
  Connection,
} from '@solana/web3.js';

const JUPITER_API_URL = 'https://lite-api.jup.ag/swap/v1';
const SOL_MINT = 'So11111111111111111111111111111111111111112';
const USDC_MINT = 'EPjFWdd5AufqSSqeM2qN1xzybapC8G4wEGGkZwyTDt1v';
const AGENT_PUBKEY = new PublicKey('AgentPubkeyPlaceholder11111111111111111111');
const RPC_URL = 'https://api.mainnet-beta.solana.com';

interface JupiterInstruction {
  programId: string;
  accounts: { pubkey: string; isSigner: boolean; isWritable: boolean }[];
  data: string;
}

function jupiterIxToTransactionInstruction(ix: JupiterInstruction): TransactionInstruction {
  return new TransactionInstruction({
    programId: new PublicKey(ix.programId),
    keys: ix.accounts.map((acc) => ({
      pubkey: new PublicKey(acc.pubkey),
      isSigner: acc.isSigner,
      isWritable: acc.isWritable,
    })),
    data: Buffer.from(ix.data, 'base64'),
  });
}

export async function executeSkill(blockhash: string): Promise<string> {
  const connection = new Connection(RPC_URL);

  // Step 1: Get a quote
  const quoteParams = new URLSearchParams({
    inputMint: SOL_MINT,
    outputMint: USDC_MINT,
    amount: '100000000', // 0.1 SOL
    slippageBps: '100',
  });

  const quoteResponse = await fetch(`${JUPITER_API_URL}/quote?${quoteParams}`);
  if (!quoteResponse.ok) {
    throw new Error(`Quote request failed: ${quoteResponse.statusText}`);
  }
  const quote = await quoteResponse.json();

  // Step 2: Get swap instructions (instead of a pre-built transaction)
  const swapInstructionsResponse = await fetch(`${JUPITER_API_URL}/swap-instructions`, {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({
      quoteResponse: quote,
      userPublicKey: AGENT_PUBKEY.toBase58(),
      dynamicComputeUnitLimit: true,
    }),
  });

  if (!swapInstructionsResponse.ok) {
    throw new Error(`Swap instructions request failed: ${swapInstructionsResponse.statusText}`);
  }
  const swapInstructions = await swapInstructionsResponse.json();

  // Step 3: Convert Jupiter instructions to TransactionInstructions
  const instructions: TransactionInstruction[] = [];

  // Add compute budget instructions
  for (const ix of swapInstructions.computeBudgetInstructions) {
    instructions.push(jupiterIxToTransactionInstruction(ix));
  }

  // Add setup instructions (token account creation, etc.)
  for (const ix of swapInstructions.setupInstructions) {
    instructions.push(jupiterIxToTransactionInstruction(ix));
  }

  // Add the main swap instruction
  instructions.push(jupiterIxToTransactionInstruction(swapInstructions.swapInstruction));

  // Add cleanup instruction if present (e.g., unwrap SOL)
  if (swapInstructions.cleanupInstruction) {
    instructions.push(jupiterIxToTransactionInstruction(swapInstructions.cleanupInstruction));
  }

  // Add other instructions (e.g., Jito tips)
  if (swapInstructions.otherInstructions) {
    for (const ix of swapInstructions.otherInstructions) {
      instructions.push(jupiterIxToTransactionInstruction(ix));
    }
  }

  // Step 4: Resolve address lookup tables
  const addressLookupTableAddresses: string[] = swapInstructions.addressLookupTableAddresses || [];
  const lookupTableAccounts: AddressLookupTableAccount[] = [];

  for (const address of addressLookupTableAddresses) {
    const result = await connection.getAddressLookupTable(new PublicKey(address));
    if (result.value) {
      lookupTableAccounts.push(result.value);
    }
  }

  // Step 5: Build the VersionedTransaction with lookup tables
  const messageV0 = new TransactionMessage({
    payerKey: AGENT_PUBKEY,
    recentBlockhash: blockhash,
    instructions,
  }).compileToV0Message(lookupTableAccounts);

  const transaction = new VersionedTransaction(messageV0);

  // Step 6: Return serialized transaction as base64
  return Buffer.from(transaction.serialize()).toString('base64');
}
