     new BN(Math.floor(TICK_LOWER / 60) * 60).toArrayLike(Buffer, 'le', 4)],
    RAYDIUM_CLMM_PROGRAM
  );
  const [tickArrayUpper] = PublicKey.findProgramAddressSync(
    [Buffer.from('tick_array'), POOL_ID.toBuffer(),
