        })
    );

    // Instruction 4: Create a new Keypair for a new mint (System Program)
    const newMintKeypair = Keypair.generate();
    // Increased lamports for mint account to ensure rent-exemption.
    const lamportsForMint = 2_000_000; // Increased to 0.002 SOL

    tx.add(
        SystemProgram.createAccount({
            fromPubkey: agentPubkey,
            newAccountPubkey: newMintKeypair.publicKey,
            lamports: lamportsForMint,
            space: MINT_SIZE,
            programId: TOKEN_PROGRAM_ID // Corrected: Use TOKEN_PROGRAM_ID
        })
    );

    // Instruction 5: Initialize the new mint (SPL Token Program)
    tx.add(
        createInitializeMint2Instruction(
            newMintKeypair.publicKey,
            6, // Decimals
            agentPubkey, // Mint Authority
            null, // Freeze Authority
            TOKEN_PROGRAM_ID // Corrected: Use TOKEN_PROGRAM_ID
        )
    );

    // Instruction 6: Create an associated token account for the agent (Associated Token Program)
    const agentATA = getAssociatedTokenAddressSync(
        newMintKeypair.publicKey,
        agentPubkey,
        false,
        TOKEN_PROGRAM_ID // Corrected: Use TOKEN_PROGRAM_ID
    );
    tx.add(
        createAssociatedTokenAccountInstruction(
            agentPubkey,
            agentATA,
            agentPubkey,
            newMintKeypair.publicKey,
            TOKEN_PROGRAM_ID, // Corrected: Use TOKEN_PROGRAM_ID
            new PublicKey("ATokenGPvbdGVxr1b2hvZbsiqW5xWH25efTNsLJA8knL") // Associated Token Program ID
        )
    );

    // Set transaction properties
    tx.recentBlockhash = blockhash;
    tx.feePayer = agentPubkey;

    // Sign with the new mint keypair
    tx.partialSign(newMintKeypair);

    // Return base64 encoded transaction
    return tx.serialize({
        requireAllSignatures: false,
        verifySignatures: false
    }).toString('base64');
}
