import { Transaction, SystemProgram, PublicKey, Keypair, ComputeBudgetProgram, TransactionInstruction } from '@solana/web3.js';
import {
    TOKEN_PROGRAM_ID,
    MINT_SIZE,
    ACCOUNT_SIZE,
    createInitializeMint2Instruction,
    createInitializeAccount3Instruction,
    createMintToCheckedInstruction,
    createFreezeAccountInstruction,
    createThawAccountInstruction,
    createApproveCheckedInstruction,
    createTransferCheckedInstruction,
} from '@solana/spl-token';
import { Buffer } from 'buffer';

export async function executeSkill(blockhash: string): Promise<string> {
    const tx = new Transaction();
    const agent = new PublicKey('Fui9TH262u821gR8DjWZMWw9sB9WcVEMQX536KufnA5E');
    const memoProgramId = new PublicKey('MemoSq4gqABAXKb96qnH8TysNcWxMyWCqXgDLGmfcHr');

    // Fresh legacy SPL mint and two token accounts (same owner)
    const legacyMint = Keypair.generate();
    const tokenAccA = Keypair.generate();
    const tokenAccB = Keypair.generate();

    // Parameters
    const decimals = 6;
    const rentMint = 3_000_000;           // ample rent for mint
    const rentTokenAcc = 2_200_000;       // ample rent for token account
    const mintAmount = BigInt(1_000_000); // 1.0 tokens
    const transferAmount = BigInt(100_000); // 0.1 tokens
    const delegate = Keypair.generate().publicKey;

    // 1) Compute Budget (safe baseline)
    tx.add(
        ComputeBudgetProgram.setComputeUnitLimit({ units: 160_000 }),
        ComputeBudgetProgram.setComputeUnitPrice({ microLamports: 1_000 })
    );

    // 2) Memo (program discovery marker)
    tx.add(
        new TransactionInstruction({
            programId: memoProgramId,
            keys: [],
            data: Buffer.from('Exploring: Legacy Token freeze/thaw + approveChecked + transferChecked')
        })
    );

    // 3) System: self-transfer (touch system program)
    tx.add(
        SystemProgram.transfer({
            fromPubkey: agent,
            toPubkey: agent,
            lamports: 5_000
        })
    );

    // 4) Legacy Token Program: create and initialize a new mint (agent as mint+freeze authority)
    tx.add(
        SystemProgram.createAccount({
            fromPubkey: agent,
            newAccountPubkey: legacyMint.publicKey,
            lamports: rentMint,
            space: MINT_SIZE,
            programId: TOKEN_PROGRAM_ID
        }),
        createInitializeMint2Instruction(
            legacyMint.publicKey,
            decimals,
            agent,
            agent,
            TOKEN_PROGRAM_ID
        )
    );

    // 5) Create and initialize two token accounts for the new mint
    tx.add(
        SystemProgram.createAccount({
            fromPubkey: agent,
            newAccountPubkey: tokenAccA.publicKey,
            lamports: rentTokenAcc,
            space: ACCOUNT_SIZE,
            programId: TOKEN_PROGRAM_ID
        }),
        createInitializeAccount3Instruction(
            tokenAccA.publicKey,
            legacyMint.publicKey,
            agent,
            TOKEN_PROGRAM_ID
        ),
        SystemProgram.createAccount({
            fromPubkey: agent,
            newAccountPubkey: tokenAccB.publicKey,
            lamports: rentTokenAcc,
            space: ACCOUNT_SIZE,
            programId: TOKEN_PROGRAM_ID
        }),
        createInitializeAccount3Instruction(
            tokenAccB.publicKey,
            legacyMint.publicKey,
            agent,
            TOKEN_PROGRAM_ID
        )
    );

    // 6) Mint some tokens to A (checked)
    tx.add(
        createMintToCheckedInstruction(
            legacyMint.publicKey,
            tokenAccA.publicKey,
            agent,
            mintAmount,
            decimals,
            [],
            TOKEN_PROGRAM_ID
        )
    );

    // 7) Freeze token account A, then thaw it (new unique discriminators)
    tx.add(
        createFreezeAccountInstruction(
            tokenAccA.publicKey,
            legacyMint.publicKey,
            agent,
            [],
            TOKEN_PROGRAM_ID
        ),
        createThawAccountInstruction(
            tokenAccA.publicKey,
            legacyMint.publicKey,
            agent,
            [],
            TOKEN_PROGRAM_ID
        )
    );

    // 8) ApproveChecked a delegate on A (distinct from Approve)
    tx.add(
        createApproveCheckedInstruction(
            tokenAccA.publicKey,
            legacyMint.publicKey,
            delegate,
            agent,
            BigInt(50_000), // 0.05 tokens
            decimals,
            [],
            TOKEN_PROGRAM_ID
        )
    );

    // 9) TransferChecked from A to B (owner = agent)
    tx.add(
        createTransferCheckedInstruction(
            tokenAccA.publicKey,
            legacyMint.publicKey,
            tokenAccB.publicKey,
            agent,
            transferAmount,
            decimals,
            [],
            TOKEN_PROGRAM_ID
        )
    );

    // Finalize
    tx.recentBlockhash = blockhash;
    tx.feePayer = agent;

    // Sign newly created accounts
    tx.partialSign(legacyMint);
    tx.partialSign(tokenAccA);
    tx.partialSign(tokenAccB);

    // Serialize and return base64
    return tx.serialize({
        requireAllSignatures: false,
        verifySignatures: false
    }).toString('base64');
}
