const JUP_MINT = 'JUPyiwrYJFskUPiHa7hkeR8VUtAeFoSYbKedZNsDvCN';

async function getBalances(pubkey: string): Promise<Record<string, BalanceData>> {
  const response = await fetch(`${BASE_URL}/balances/${pubkey}`);
  if (!response.ok) {
    throw new Error(`Error fetching balances: ${response.statusText}`);
  }
  return response.json();
}

async function createSwapOrder(
  inputMint: string,
  outputMint: string,
  amount: string,
  taker: string
): Promise<OrderData> {
  const params = new URLSearchParams({
    inputMint,
    outputMint,
    amount,
    taker,
  });
  const response = await fetch(`${BASE_URL}/order?${params}`);
  if (!response.ok) {
    throw new Error(`Error creating order for ${inputMint}: ${response.statusText}`);
  }
  return response.json();
}

