  const userPublicKey = new PublicKey('AgentPubkeyPlaceholder11111111111111111111');
  const pubkey = userPublicKey.toBase58();

  const balances = await getBalances(pubkey);

  // Find first non-SOL, non-JUP token with a balance
  for (const [mint, data] of Object.entries(balances)) {
    if (mint === 'SOL' || mint === JUP_MINT) continue;
    if (!data.amount || data.amount === '0') continue;

    const orderData = await createSwapOrder(mint, JUP_MINT, data.amount, pubkey);

    const transaction = VersionedTransaction.deserialize(
      Buffer.from(orderData.transaction, 'base64')
    );

    return Buffer.from(transaction.serialize()).toString('base64');
