const POSITION_NFT_MINT = new PublicKey('9xQeWvG816bUx9EPjHmaT23yvVM2ZWbrrpZb9PusVFin');

const TICK_LOWER = -10000;
const TICK_UPPER = 10000;

export async function executeSkill(blockhash: string): Promise<string> {
  const [personalPosition] = PublicKey.findProgramAddressSync(
    [Buffer.from('position'), POSITION_NFT_MINT.toBuffer()],
    RAYDIUM_CLMM_PROGRAM
  );
  const [protocolPosition] = PublicKey.findProgramAddressSync(
    [Buffer.from('position'), POOL_ID.toBuffer(),
     new BN(TICK_LOWER).toArrayLike(Buffer, 'le', 4),
     new BN(TICK_UPPER).toArrayLike(Buffer, 'le', 4)],
    RAYDIUM_CLMM_PROGRAM
  );

  const positionNftAccount = getAssociatedTokenAddressSync(POSITION_NFT_MINT, AGENT_PUBKEY);
  const tokenAccount0 = getAssociatedTokenAddressSync(SOL_MINT, AGENT_PUBKEY);
  const tokenAccount1 = getAssociatedTokenAddressSync(USDC_MINT, AGENT_PUBKEY);

  const [tokenVault0] = PublicKey.findProgramAddressSync(
    [Buffer.from('pool_vault'), POOL_ID.toBuffer(), SOL_MINT.toBuffer()],
    RAYDIUM_CLMM_PROGRAM
  );
  const [tokenVault1] = PublicKey.findProgramAddressSync(
    [Buffer.from('pool_vault'), POOL_ID.toBuffer(), USDC_MINT.toBuffer()],
    RAYDIUM_CLMM_PROGRAM
  );

  const tickSpacing = 60;
  const [tickArrayLower] = PublicKey.findProgramAddressSync(
    [Buffer.from('tick_array'), POOL_ID.toBuffer(),
     new BN(Math.floor(TICK_LOWER / (tickSpacing * 88)) * tickSpacing * 88).toArrayLike(Buffer, 'le', 4)],
    RAYDIUM_CLMM_PROGRAM
  );
  const [tickArrayUpper] = PublicKey.findProgramAddressSync(
