     new BN(Math.floor(TICK_UPPER / (tickSpacing * 88)) * tickSpacing * 88).toArrayLike(Buffer, 'le', 4)],
    RAYDIUM_CLMM_PROGRAM
  );

  // Collect fees: decrease liquidity by 0 triggers fee collection
  const collectData = Buffer.alloc(33);
  collectData.writeUInt8(3, 0); // decrease_liquidity with 0 = collect fees
  new BN(0).toArrayLike(Buffer, 'le', 16).copy(collectData, 1); // 0 liquidity
  new BN(0).toArrayLike(Buffer, 'le', 8).copy(collectData, 17); // min amount 0
  new BN(0).toArrayLike(Buffer, 'le', 8).copy(collectData, 25); // min amount 1

  const collectIx = new TransactionInstruction({
    programId: RAYDIUM_CLMM_PROGRAM,
