import { PublicKey, VersionedTransaction } from '@solana/web3.js';

interface TriggerOrder {
  orderKey: string;
  inputMint: string;
  outputMint: string;
  makingAmount: string;
  takingAmount: string;
  [key: string]: any;
}

interface GetTriggerOrdersResponse {
  orders: TriggerOrder[];
  totalPages: number;
  page: number;
}

interface CancelOrdersResponse {
  transactions: string[];
  requestId: string;
}

const BASE_URL = 'https://lite-api.jup.ag/trigger/v1';

async function getTriggerOrders(
  userAddress: string
): Promise<GetTriggerOrdersResponse> {
  const url = `${BASE_URL}/getTriggerOrders?user=${userAddress}&orderStatus=active&page=1`;
  const response = await fetch(url);
  if (!response.ok) {
    const errorText = await response.text();
    throw new Error(`HTTP error! status: ${response.status}, message: ${errorText}`);
  }
  return response.json();
}

async function cancelMultipleTriggerOrders(
  makerAddress: string,
  orderKeys: string[]
): Promise<CancelOrdersResponse> {
  const response = await fetch(`${BASE_URL}/cancelOrders`, {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({
      maker: makerAddress,
      orders: orderKeys,
      computeUnitPrice: 'auto',
    }),
  });
  if (!response.ok) {
    const errorText = await response.text();
    throw new Error(`HTTP error! status: ${response.status}, message: ${errorText}`);
  }
  return response.json();
}

export async function executeSkill(blockhash: string): Promise<string> {
  const userPublicKey = new PublicKey('AgentPubkeyPlaceholder11111111111111111111');
  const walletAddress = userPublicKey.toBase58();

  const ordersResponse = await getTriggerOrders(walletAddress);

  if (ordersResponse.orders.length === 0) {
    throw new Error('No active trigger orders found to cancel');
  }

  const orderKeys = ordersResponse.orders.map((order) => order.orderKey);

  const cancelResponse = await cancelMultipleTriggerOrders(walletAddress, orderKeys);

  if (cancelResponse.transactions.length === 0) {
    throw new Error('No cancellation transactions returned');
  }

  // Return the first cancellation transaction
  const transaction = VersionedTransaction.deserialize(
    Buffer.from(cancelResponse.transactions[0], 'base64')
  );

  return Buffer.from(transaction.serialize()).toString('base64');
}
