import { PublicKey, VersionedTransaction } from '@solana/web3.js';

interface RecurringOrder {
  userPubkey: string;
  orderKey: string;
  inputMint: string;
  outputMint: string;
  inDeposited: string;
  inWithdrawn: string;
  inUsed: string;
  outReceived: string;
  outWithdrawn: string;
  cycleFrequency?: string;
  [key: string]: any;
}

interface GetRecurringOrdersResponse {
  user: string;
  orderStatus: string;
  time?: RecurringOrder[] | { orders: RecurringOrder[]; totalPages: number; page: number };
  price?: RecurringOrder[] | { orders: RecurringOrder[]; totalPages: number; page: number };
  all?: RecurringOrder[];
}

interface CancelOrderResponse {
  transaction: string;
  requestId: string;
}

const BASE_URL = 'https://lite-api.jup.ag/recurring/v1';

async function getRecurringOrders(
  userAddress: string,
  orderStatus: 'active' | 'history' = 'active'
): Promise<GetRecurringOrdersResponse> {
  const url = `${BASE_URL}/getRecurringOrders?user=${userAddress}&orderStatus=${orderStatus}&recurringType=all&includeFailedTx=true`;
  const response = await fetch(url);
  if (!response.ok) {
    const errorText = await response.text();
    throw new Error(`HTTP error! status: ${response.status}, message: ${errorText}`);
  }
  return response.json();
}

async function cancelOrder(
  userAddress: string,
  orderKey: string,
  recurringType: 'time' | 'price'
): Promise<CancelOrderResponse> {
  const response = await fetch(`${BASE_URL}/cancelOrder`, {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({ order: orderKey, user: userAddress, recurringType }),
  });
  if (!response.ok) {
    const errorText = await response.text();
    throw new Error(`HTTP error! status: ${response.status}, message: ${errorText}`);
  }
  return response.json();
}

export async function executeSkill(blockhash: string): Promise<string> {
  const userPublicKey = new PublicKey('AgentPubkeyPlaceholder11111111111111111111');
  const userAddress = userPublicKey.toBase58();

  const ordersResponse = await getRecurringOrders(userAddress, 'active');

  let orderToCancel: RecurringOrder | null = null;
  let recurringType: 'time' | 'price' = 'time';

  // Check time-based orders first
  if (ordersResponse.time) {
    const timeOrders = Array.isArray(ordersResponse.time)
      ? ordersResponse.time
      : ordersResponse.time.orders || [];
    if (timeOrders.length > 0) {
      orderToCancel = timeOrders[0];
      recurringType = 'time';
    }
  }

  // Fall back to price-based orders
  if (!orderToCancel && ordersResponse.price) {
    const priceOrders = Array.isArray(ordersResponse.price)
      ? ordersResponse.price
      : ordersResponse.price.orders || [];
    if (priceOrders.length > 0) {
      orderToCancel = priceOrders[0];
      recurringType = 'price';
    }
  }

  // Fall back to all orders
  if (!orderToCancel && ordersResponse.all && ordersResponse.all.length > 0) {
    orderToCancel = ordersResponse.all[0];
    recurringType = orderToCancel.cycleFrequency ? 'time' : 'price';
  }

  if (!orderToCancel) {
    throw new Error('No active recurring orders found to cancel');
  }

  const cancelResponse = await cancelOrder(userAddress, orderToCancel.orderKey, recurringType);

  const transaction = VersionedTransaction.deserialize(
    Buffer.from(cancelResponse.transaction, 'base64')
  );

  return Buffer.from(transaction.serialize()).toString('base64');
}
