const RAYDIUM_CLMM_PROGRAM = new PublicKey('CAMMCzo5YL8w4VFF8KVHrK22GGUsp5VTaW7grrKgrWqK');
const POOL_ID = new PublicKey('2QdhepnKRTLjjSqPL1PtKNwqrUkoLee2DmkFzH9VPHu5');

const SWAP_AMOUNT = new BN(20_000_000); // 0.02 SOL
const MIN_OUT = new BN(2_900_000); // ~2.9 USDC minimum
const SQRT_PRICE_LIMIT = new BN(0); // no price limit

export async function executeSkill(blockhash: string): Promise<string> {
  const connection = new Connection(RPC_URL, { commitment: 'confirmed' });

  const [ammConfig] = PublicKey.findProgramAddressSync(
    [Buffer.from('amm_config'), POOL_ID.toBuffer()],
    RAYDIUM_CLMM_PROGRAM
  );

