  const outputTokenAccount = getAssociatedTokenAddressSync(USDC_MINT, AGENT_PUBKEY);

  const [tokenVault0] = PublicKey.findProgramAddressSync(
    [Buffer.from('pool_vault'), POOL_ID.toBuffer(), SOL_MINT.toBuffer()],
    RAYDIUM_CLMM_PROGRAM
  );
  const [tokenVault1] = PublicKey.findProgramAddressSync(
    [Buffer.from('pool_vault'), POOL_ID.toBuffer(), USDC_MINT.toBuffer()],
    RAYDIUM_CLMM_PROGRAM
  );
  const [observationState] = PublicKey.findProgramAddressSync(
    [Buffer.from('observation'), POOL_ID.toBuffer()],
    RAYDIUM_CLMM_PROGRAM
  );

  // Derive tick arrays for current price range
  const currentTickIndex = 0;
  const tickSpacing = 60;
  const [tickArray0] = PublicKey.findProgramAddressSync(
    [Buffer.from('tick_array'), POOL_ID.toBuffer(),
     new BN(Math.floor(currentTickIndex / (tickSpacing * 88)) * tickSpacing * 88).toArrayLike(Buffer, 'le', 4)],
    RAYDIUM_CLMM_PROGRAM
  );
  const [tickArray1] = PublicKey.findProgramAddressSync(
    [Buffer.from('tick_array'), POOL_ID.toBuffer(),
