const RAYDIUM_CPMM_PROGRAM = new PublicKey('CPMMoo8L3F4NbTegBCKVNunggL7H1ZpdTHKxQB5qKP1C');
const INITIAL_SOL = 1_000_000_000; // 1 SOL in lamports
const INITIAL_TOKEN = 1_000_000_000; // 1000 tokens (assuming 6 decimals)

export async function executeSkill(blockhash: string): Promise<string> {
  const connection = new Connection(RPC_URL, { commitment: 'confirmed' });

  // Generate keypairs for pool accounts
  const poolState = Keypair.generate();
  const lpMint = Keypair.generate();

  // Derive PDAs for the pool
  const [authority] = PublicKey.findProgramAddressSync(
    [Buffer.from('vault_and_lp_mint_auth_seed')],
    RAYDIUM_CPMM_PROGRAM
  );
  const [tokenVault0] = PublicKey.findProgramAddressSync(
    [Buffer.from('pool_vault'), poolState.publicKey.toBuffer(), SOL_MINT.toBuffer()],
    RAYDIUM_CPMM_PROGRAM
  );
  const [tokenVault1] = PublicKey.findProgramAddressSync(
    [Buffer.from('pool_vault'), poolState.publicKey.toBuffer(), CUSTOM_TOKEN_MINT.toBuffer()],
    RAYDIUM_CPMM_PROGRAM
  );
  const [observationState] = PublicKey.findProgramAddressSync(
    [Buffer.from('observation'), poolState.publicKey.toBuffer()],
    RAYDIUM_CPMM_PROGRAM
  );

  const userTokenAccount0 = getAssociatedTokenAddressSync(SOL_MINT, AGENT_PUBKEY);
  const userTokenAccount1 = getAssociatedTokenAddressSync(CUSTOM_TOKEN_MINT, AGENT_PUBKEY);
  const userLpAccount = getAssociatedTokenAddressSync(lpMint.publicKey, AGENT_PUBKEY);

  const openTime = new BN(Math.floor(Date.now() / 1000) + 60);

  // Build initialize pool instruction
  const initPoolData = Buffer.alloc(41);
  initPoolData.writeUInt8(0, 0); // instruction index for initialize
  new BN(INITIAL_SOL).toArrayLike(Buffer, 'le', 8).copy(initPoolData, 1);
  new BN(INITIAL_TOKEN).toArrayLike(Buffer, 'le', 8).copy(initPoolData, 9);
  openTime.toArrayLike(Buffer, 'le', 8).copy(initPoolData, 17);

  const initPoolIx = new TransactionInstruction({
    programId: RAYDIUM_CPMM_PROGRAM,
    keys: [
      { pubkey: AGENT_PUBKEY, isSigner: true, isWritable: true },
      { pubkey: authority, isSigner: false, isWritable: false },
      { pubkey: poolState.publicKey, isSigner: true, isWritable: true },
      { pubkey: SOL_MINT, isSigner: false, isWritable: false },
      { pubkey: CUSTOM_TOKEN_MINT, isSigner: false, isWritable: false },
      { pubkey: lpMint.publicKey, isSigner: true, isWritable: true },
      { pubkey: userTokenAccount0, isSigner: false, isWritable: true },
      { pubkey: userTokenAccount1, isSigner: false, isWritable: true },
      { pubkey: userLpAccount, isSigner: false, isWritable: true },
      { pubkey: tokenVault0, isSigner: false, isWritable: true },
      { pubkey: tokenVault1, isSigner: false, isWritable: true },
      { pubkey: observationState, isSigner: false, isWritable: true },
      { pubkey: TOKEN_PROGRAM_ID, isSigner: false, isWritable: false },
      { pubkey: SystemProgram.programId, isSigner: false, isWritable: false },
      { pubkey: SYSVAR_RENT_PUBKEY, isSigner: false, isWritable: false },
    ],
    data: initPoolData,
  });

  const tx = new Transaction({
    blockhash,
    lastValidBlockHeight: 0,
    feePayer: AGENT_PUBKEY,
  });
  tx.add(initPoolIx);

  return tx.serialize({ requireAllSignatures: false, verifySignatures: false }).toString('base64');
}
