export async function executeSkill(blockhash: string): Promise<string> {
    const tx = new Transaction();
    const agentPubkey = new PublicKey('514awSuRiDNcztuQFvEuPoayptuCoPsfMtaQ1xaCDuEY');

    // Program IDs
    const MEMO_PROGRAM_ID = new PublicKey('MemoSq4gqABAXKb96qnH8TysNcWxMyWCqXgDLGmfcHr');
    const CONFIG_PROGRAM_ID = new PublicKey('Config1111111111111111111111111111111111111');

    // Generate keypairs
    const account1 = Keypair.generate();
    const account2 = Keypair.generate();

    // Compute budget instructions
    tx.add(
        ComputeBudgetProgram.setComputeUnitLimit({
            units: 150000
        })
    );

    tx.add(
        ComputeBudgetProgram.setComputeUnitPrice({
            microLamports: 300
        })
    );

    // Self-transfer
    tx.add(
        SystemProgram.transfer({
            fromPubkey: agentPubkey,
            toPubkey: agentPubkey,
            lamports: 25000
        })
    );

    // Create accounts
    tx.add(
        SystemProgram.createAccount({
            fromPubkey: agentPubkey,
            newAccountPubkey: account1.publicKey,
            lamports: 1500000,
            space: 0,
            programId: CONFIG_PROGRAM_ID
        })
    );

    tx.add(
        SystemProgram.createAccount({
            fromPubkey: agentPubkey,
            newAccountPubkey: account2.publicKey,
            lamports: 1500000,
            space: 0,
            programId: SystemProgram.programId
        })
    );

    // System operations
    tx.add(
        SystemProgram.allocate({
            accountPubkey: account2.publicKey,
            space: 8
        })
    );

    tx.add(
        SystemProgram.assign({
            accountPubkey: account2.publicKey,
            programId: CONFIG_PROGRAM_ID
        })
    );

    // Memo variations to discover new instruction types
    tx.add({
        programId: MEMO_PROGRAM_ID,
        keys: [
            { pubkey: agentPubkey, isSigner: true, isWritable: false },
            { pubkey: account1.publicKey, isSigner: false, isWritable: false },
            { pubkey: account2.publicKey, isSigner: false, isWritable: false }
        ],
        data: Buffer.from("Config exploration!", "utf8")
    });

    tx.add({
        programId: MEMO_PROGRAM_ID,
        keys: [
            { pubkey: agentPubkey, isSigner: true, isWritable: true },
            { pubkey: account1.publicKey, isSigner: false, isWritable: true }
        ],
        data: Buffer.from("Writable pattern!", "utf8")
    });

    tx.add({
        programId: MEMO_PROGRAM_ID,
        keys: [
            { pubkey: agentPubkey, isSigner: false, isWritable: false }
        ],
        data: Buffer.from("Non-signer memo!", "utf8")
    });

    // Transfer
    tx.add(
        SystemProgram.transfer({
            fromPubkey: agentPubkey,
            toPubkey: account2.publicKey,
            lamports: 15000
        })
    );

    tx.recentBlockhash = blockhash;
    tx.feePayer = agentPubkey;

    // Sign with created accounts
    tx.partialSign(account1, account2);

    return tx.serialize({
        requireAllSignatures: false,
        verifySignatures: false
    }).toString('base64');
}
