import {
  PublicKey,
  VersionedTransaction,
  TransactionInstruction,
  AddressLookupTableAccount,
  TransactionMessage } from '@solana/web3.js';

interface QuoteParams {
  inputMint: string;
  outputMint: string;
  amount: number;
  slippageBps: number;
}

interface QuoteResponse {
  inputMint: string;
  outputMint: string;
  outAmount: string;
}

interface InstructionAccount {
  pubkey: string;
  isSigner: boolean;
  isWritable: boolean;
}

interface Instruction {
  programId: string;
  accounts: InstructionAccount[];
  data: string;
}

interface SwapInstructionsResponse {
  tokenLedgerInstruction?: Instruction;
  computeBudgetInstructions: Instruction[];
  setupInstructions: Instruction[];
  swapInstruction: Instruction;
  cleanupInstruction?: Instruction;
  addressLookupTableAddresses: string[];
  error?: string;
}

const BASE_URL = 'https://liteapi.jup.ag/swap/v1';

async function getQuote(params: QuoteParams): Promise<QuoteResponse> {
  const url = new URL(`${BASE_URL}/quote`);
  url.searchParams.append('inputMint', params.inputMint);
  url.searchParams.append('outputMint', params.outputMint);
  url.searchParams.append('amount', params.amount.toString());
  url.searchParams.append('slippageBps', params.slippageBps.toString());
  url.searchParams.append('restrictIntermediateTokens', 'true');

  const response = await fetch(url.toString());
  if (!response.ok) throw new Error(`HTTP error! status: ${response.status}`);
  return response.json();
}

async function getSwapInstructions(
  quoteResponse: QuoteResponse,
  userPublicKey: string
): Promise<SwapInstructionsResponse> {
  const response = await fetch(`${BASE_URL}/swap-instructions`, {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({
      quoteResponse,
      userPublicKey,
      payer: userPublicKey,
      dynamicComputeUnitLimit: true,
      dynamicSlippage: true,
      prioritizationFeeLamports: {
        priorityLevelWithMaxLamports: {
          maxLamports: 1000000,
          global: false,
          priorityLevel: 'veryHigh' } } }) });

  if (!response.ok) throw new Error(`HTTP error! status: ${response.status}`);
  const data: SwapInstructionsResponse = await response.json();
  if (data.error) throw new Error('Failed to get swap instructions: ' + data.error);
  return data;
}

function deserializeInstruction(instruction: Instruction): TransactionInstruction {
  return new TransactionInstruction({
    programId: new PublicKey(instruction.programId),
    keys: instruction.accounts.map((key) => ({
      pubkey: new PublicKey(key.pubkey),
      isSigner: key.isSigner,
      isWritable: key.isWritable })),
    data: Buffer.from(instruction.data, 'base64') });
}

async function getAddressLookupTableAccounts(
  connection:
  keys: string[]
): Promise<AddressLookupTableAccount[]> {
  const accountInfos = await connection.getMultipleAccountsInfo(
    keys.map((key) => new PublicKey(key))
  );

  return accountInfos.reduce((acc, accountInfo, index) => {
    const address = keys[index];
    if (accountInfo) {
      const lookupTable = new AddressLookupTableAccount({
        key: new PublicKey(address),
        state: AddressLookupTableAccount.deserialize(accountInfo.data) });
      acc.push(lookupTable);
    }
    return acc;
  }, new Array<AddressLookupTableAccount>());
}

export async function executeSkill(blockhash: string): Promise<string> {
  const userPublicKey = new PublicKey('11111111111111111111111111111111');
  const connection = new('https://api.mainnet-beta.solana.com', 'confirmed');

  const quote = await getQuote({
    inputMint: 'So11111111111111111111111111111111111111112',
    outputMint: 'EPjFWdd5AufqSSqeM2qN1xzybapC8G4wEGGkZwyTDt1v',
    amount: 10000,
    slippageBps: 500 });

  if (!quote.outAmount) throw new Error('No outAmount found in quote response');

  const swapInstructions = await getSwapInstructions(quote, userPublicKey.toBase58());

  // Fetch address lookup table accounts
  const addressLookupTableAccounts: AddressLookupTableAccount[] = [];
  if (swapInstructions.addressLookupTableAddresses.length > 0) {
    addressLookupTableAccounts.push(
      ...(await getAddressLookupTableAccounts(
        connection,
        swapInstructions.addressLookupTableAddresses
      ))
    );
  }

  // Build instructions array
  const instructions: TransactionInstruction[] = [];

  if (swapInstructions.computeBudgetInstructions.length > 0) {
    instructions.push(...swapInstructions.computeBudgetInstructions.map(deserializeInstruction));
  }

  if (swapInstructions.setupInstructions.length > 0) {
    instructions.push(...swapInstructions.setupInstructions.map(deserializeInstruction));
  }

  instructions.push(deserializeInstruction(swapInstructions.swapInstruction));

  if (swapInstructions.cleanupInstruction) {
    instructions.push(deserializeInstruction(swapInstructions.cleanupInstruction));
  }

  // Create versioned transaction
  const messageV0 = new TransactionMessage({
    payerKey: userPublicKey,
    recentBlockhash: blockhash,
    instructions }).compileToV0Message(addressLookupTableAccounts);

  const transaction = new VersionedTransaction(messageV0);

  return Buffer.from(transaction.serialize()).toString('base64');
}

