import { Keypair, PublicKey, Transaction, TransactionInstruction, SystemProgram } from '@solana/web3.js';
import { getAssociatedTokenAddressSync, TOKEN_PROGRAM_ID, ASSOCIATED_TOKEN_PROGRAM_ID } from '@solana/spl-token';
import { Buffer } from 'buffer';
import BN from 'bn.js';

const PROGRAM_ID = new PublicKey('11111111111111111111111111111111');
const PLACEHOLDER_PUBKEY = new PublicKey('11111111111111111111111111111111');

export async function executeSkill(blockhash: string): Promise<string> {
  const admin = Keypair.generate();
  const id = Keypair.generate().publicKey;
  const fee = 500;

  // Derive AMM PDA
  const [ammKey] = PublicKey.findProgramAddressSync([id.toBuffer()], PROGRAM_ID);

  // Generate mint keypairs ensuring mintB > mintA in byte order
  const mintA = Keypair.generate();
  let mintB = Keypair.generate();
  while (new BN(mintB.publicKey.toBytes()).lt(new BN(mintA.publicKey.toBytes()))) {
    mintB = Keypair.generate();
  }

  // Derive pool-related PDAs
  const [poolAuthority] = PublicKey.findProgramAddressSync(
    [ammKey.toBuffer(), mintA.publicKey.toBuffer(), mintB.publicKey.toBuffer(), Buffer.from('authority')],
    PROGRAM_ID,
  );
  const [mintLiquidity] = PublicKey.findProgramAddressSync(
    [ammKey.toBuffer(), mintA.publicKey.toBuffer(), mintB.publicKey.toBuffer(), Buffer.from('liquidity')],
    PROGRAM_ID,
  );
  const [poolKey] = PublicKey.findProgramAddressSync(
    [ammKey.toBuffer(), mintA.publicKey.toBuffer(), mintB.publicKey.toBuffer()],
    PROGRAM_ID,
  );

  const poolAccountA = getAssociatedTokenAddressSync(mintA.publicKey, poolAuthority, true);
  const poolAccountB = getAssociatedTokenAddressSync(mintB.publicKey, poolAuthority, true);
  const traderAccountA = getAssociatedTokenAddressSync(mintA.publicKey, admin.publicKey, true);
  const traderAccountB = getAssociatedTokenAddressSync(mintB.publicKey, admin.publicKey, true);

  // Instruction 1: createAmm(id, fee)
  const createAmmData = Buffer.concat([
    Buffer.from([0x01]),
    id.toBuffer(),
    Buffer.from(new Uint16Array([fee]).buffer),
  ]);
  const createAmmIx = new TransactionInstruction({
    keys: [
      { pubkey: admin.publicKey, isSigner: true, isWritable: true },
      { pubkey: ammKey, isSigner: false, isWritable: true },
      { pubkey: SystemProgram.programId, isSigner: false, isWritable: false },
    ],
    programId: PROGRAM_ID,
    data: createAmmData,
  });

  // Instruction 2: createPool
  const createPoolData = Buffer.from([0x02]);
  const createPoolIx = new TransactionInstruction({
    keys: [
      { pubkey: admin.publicKey, isSigner: true, isWritable: true },
      { pubkey: ammKey, isSigner: false, isWritable: false },
      { pubkey: poolKey, isSigner: false, isWritable: true },
      { pubkey: poolAuthority, isSigner: false, isWritable: false },
      { pubkey: mintLiquidity, isSigner: false, isWritable: true },
      { pubkey: mintA.publicKey, isSigner: false, isWritable: false },
      { pubkey: mintB.publicKey, isSigner: false, isWritable: false },
      { pubkey: poolAccountA, isSigner: false, isWritable: true },
      { pubkey: poolAccountB, isSigner: false, isWritable: true },
      { pubkey: TOKEN_PROGRAM_ID, isSigner: false, isWritable: false },
      { pubkey: ASSOCIATED_TOKEN_PROGRAM_ID, isSigner: false, isWritable: false },
      { pubkey: SystemProgram.programId, isSigner: false, isWritable: false },
    ],
    programId: PROGRAM_ID,
    data: createPoolData,
  });

  // Instruction 3: swapExactTokensForTokens(true, 1_000_000, 100)
  const swapInput = new BN(1_000_000);
  const minOutput = new BN(100);
  const swapData = Buffer.concat([
    Buffer.from([0x04]),
    Buffer.from([0x01]),
    swapInput.toArrayLike(Buffer, 'le', 8),
    minOutput.toArrayLike(Buffer, 'le', 8),
  ]);
  const swapIx = new TransactionInstruction({
    keys: [
      { pubkey: admin.publicKey, isSigner: true, isWritable: false },
      { pubkey: ammKey, isSigner: false, isWritable: false },
      { pubkey: poolKey, isSigner: false, isWritable: true },
      { pubkey: poolAuthority, isSigner: false, isWritable: false },
      { pubkey: mintA.publicKey, isSigner: false, isWritable: false },
      { pubkey: mintB.publicKey, isSigner: false, isWritable: false },
      { pubkey: poolAccountA, isSigner: false, isWritable: true },
      { pubkey: poolAccountB, isSigner: false, isWritable: true },
      { pubkey: traderAccountA, isSigner: false, isWritable: true },
      { pubkey: traderAccountB, isSigner: false, isWritable: true },
      { pubkey: TOKEN_PROGRAM_ID, isSigner: false, isWritable: false },
    ],
    programId: PROGRAM_ID,
    data: swapData,
  });

  const tx = new Transaction();
  tx.recentBlockhash = blockhash;
  tx.feePayer = admin.publicKey;
  tx.add(createAmmIx, createPoolIx, swapIx);

  const serialized = tx.serialize({ requireAllSignatures: false, verifySignatures: false });
  return Buffer.from(serialized).toString('base64');
}
