const RAYDIUM_CLMM_PROGRAM = new PublicKey('CAMMCzo5YL8w4VFF8KVHrK22GGUsp5VTaW7grrKgrWqK');
const POOL_ID = new PublicKey('2QdhepnKRTLjjSqPL1PtKNwqrUkoLee2DmkFzH9VPHu5'); // SOL/USDC CLMM pool

const TICK_LOWER = -10000; // Lower price bound tick
const TICK_UPPER = 10000;  // Upper price bound tick
const LIQUIDITY_AMOUNT = new BN('1000000000'); // liquidity units
const AMOUNT_0_MAX = new BN('100000000');  // max 0.1 SOL
const AMOUNT_1_MAX = new BN('15000000');   // max 15 USDC

export async function executeSkill(blockhash: string): Promise<string> {
  const connection = new(RPC_URL, { commitment: 'confirmed' });

  // Generate position NFT mint
  const positionNftMint = Keypair.generate();

  // Derive PDAs
  const [protocolPosition] = PublicKey.findProgramAddressSync(
    [Buffer.from('position'), POOL_ID.toBuffer(), 
     new BN(TICK_LOWER).toArrayLike(Buffer, 'le', 4),
     new BN(TICK_UPPER).toArrayLike(Buffer, 'le', 4)],
    RAYDIUM_CLMM_PROGRAM
  );
  const [personalPosition] = PublicKey.findProgramAddressSync(
    [Buffer.from('position'), positionNftMint.publicKey.toBuffer()],
    RAYDIUM_CLMM_PROGRAM
  );
  const [tickArrayLower] = PublicKey.findProgramAddressSync(
    [Buffer.from('tick_array'), POOL_ID.toBuffer(),
     new BN(Math.floor(TICK_LOWER / 60) * 60).toArrayLike(Buffer, 'le', 4)],
    RAYDIUM_CLMM_PROGRAM
  );
  const [tickArrayUpper] = PublicKey.findProgramAddressSync(
    [Buffer.from('tick_array'), POOL_ID.toBuffer(),
     new BN(Math.floor(TICK_UPPER / 60) * 60).toArrayLike(Buffer, 'le', 4)],
    RAYDIUM_CLMM_PROGRAM
