    RAYDIUM_CLMM_PROGRAM
  );

  // Build open position instruction
  const openPosData = Buffer.alloc(45);
  openPosData.writeUInt8(0, 0); // discriminator for open_position
  new BN(TICK_LOWER).toArrayLike(Buffer, 'le', 4).copy(openPosData, 1);
  new BN(TICK_UPPER).toArrayLike(Buffer, 'le', 4).copy(openPosData, 5);
  LIQUIDITY_AMOUNT.toArrayLike(Buffer, 'le', 16).copy(openPosData, 9);
  AMOUNT_0_MAX.toArrayLike(Buffer, 'le', 8).copy(openPosData, 25);
  AMOUNT_1_MAX.toArrayLike(Buffer, 'le', 8).copy(openPosData, 33);

