import {
    PublicKey,
    Transaction } from '@solana/web3.js';
import { NATIVE_MINT } from '@solana/spl-token';

// ---------------------------------------------------------------
// Constants
// ---------------------------------------------------------------
const AGENT_PUBKEY = new PublicKey(
    '6rMnR6ncmMzzjcgGj5VixMS8u7U6ggH6o4iSbkyUoQ2L'
);
const USDC_MINT = new PublicKey(
    'EPjFWdd5AufqSSqeM2qN1xzybapC8G4wEGGkZwyTDt1v'
);

// ---------------------------------------------------------------
// Required entry point
// ---------------------------------------------------------------
export async function executeSkill(blockhash: string): Promise<string> {
    // 1️⃣  Connect to the sandbox RPC (kept for completeness)
    const connection = new('http://localhost:8899');

    // 2️⃣  Get a quote from Jupiter (swap 0.001 SOL → USDC, 1 % slippage)
    const quoteUrl = new URL('https://quote-api.jup.ag/v6/quote');
    quoteUrl.searchParams.set('inputMint',  NATIVE_MINT.toBase58()); // Wrapped SOL
    quoteUrl.searchParams.set('outputMint', USDC_MINT.toBase58());   // USDC
    quoteUrl.searchParams.set('amount',      '1000000');           // 0.001 SOL (lamports)
    quoteUrl.searchParams.set('slippageBps','100');                // 1 % slippage

    const quoteResp = await fetch(quoteUrl.toString());
    const quote = await quoteResp.json();

    if (quote.error) {
        throw new Error(`Jupiter quote error: ${quote.error}`);
    }

    // 3️⃣  Request a **legacy** swap transaction from Jupiter.
    //     The flag `asLegacyTransaction: true` forces Jupiter to give us a
    //     non‑versioned transaction (easier for the sandbox to handle).
    const swapResp = await fetch('https://quote-api.jup.ag/v6/swap', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
            quoteResponse: quote,
            userPublicKey: AGENT_PUBKEY.toBase58(),
            wrapAndUnwrapSol: true,
            asLegacyTransaction: true,
            dynamicComputeUnitLimit: true,
            prioritizationFeeLamports: 'auto' }) });

    const swapData = await swapResp.json();

    if (!swapData.swapTransaction) {
        throw new Error(`Jupiter swap error: ${JSON.stringify(swapData)}`);
    }

    // 4️⃣  Decode the legacy transaction.
    const txBuf = Buffer.from(swapData.swapTransaction, 'base64');
    const transaction = Transaction.from(txBuf); // legacy Transaction

    // Replace the recent blockhash with the one supplied by the runner.
    transaction.recentBlockhash = blockhash;

    // Ensure the fee payer is the agent (Jupiter already sets it, but we set it
    // explicitly for safety).
    transaction.feePayer = AGENT_PUBKEY;

    // **Important:** Remove any signatures that came from the fetched transaction.
    // The sandbox will sign the transaction with the agent's private key.
    transaction.signatures = [];

    // Serialize without requiring all signatures (the sandbox will add the real one).
    const serialized = transaction.serialize({ requireAllSignatures: false });

    // Return a strict Base‑64 encoded transaction.
    return Buffer.from(serialized).toString('base64');
}

