    // Ensure the fee payer is the agent (Jupiter already sets it, but we set it
    // explicitly for safety).
    transaction.feePayer = AGENT_PUBKEY;

    // **Important:** Remove any signatures that came from the fetched transaction.
    // The sandbox will sign the transaction with the agent's private key.
    transaction.signatures = [];

    // Serialize without requiring all signatures (the sandbox will add the real one).
    const serialized = transaction.serialize({ requireAllSignatures: false });

    // Return a strict Base‑64 encoded transaction.
    return Buffer.from(serialized).toString('base64');
