export async function executeSkill(blockhash: string): Promise<string> {
    const tx = new Transaction();
    const agentPubkey = new PublicKey('3jzEHwrkRJyGnbLunKRPxVWF84uwhWX3685rPxA7jCuh');

    // Keep compute budget lean (avoid large instructions)
    tx.add(
        ComputeBudgetProgram.setComputeUnitLimit({ units: 200_000 }),
        ComputeBudgetProgram.setComputeUnitPrice({ microLamports: 1 }),
    );

    // Small memo for traceability
    const memoProgramId = new PublicKey('MemoSq4gqABAXKb96qnH8TysNcWxMyWCqXgDLGmfcHr');
    tx.add(new TransactionInstruction({
        programId: memoProgramId,
        keys: [],
        data: Buffer.from(`Explorer compact - ${new Date().toISOString()}`),
    }));

    // SPL Token operations on WSOL ATA (unique Token instructions)
    const wsolMint = new PublicKey('So11111111111111111111111111111111111111112');
    const wsolAta = getAssociatedTokenAddressSync(
        wsolMint,
        agentPubkey,
        false,
        TOKEN_PROGRAM_ID,
        ASSOCIATED_TOKEN_PROGRAM_ID
    );
    const delegate = Keypair.generate().publicKey;

    tx.add(
        // Approve delegate
        createApproveInstruction(wsolAta, delegate, agentPubkey, 1n),
        // ApproveChecked with decimals (WSOL = 9)
        createApproveCheckedInstruction(wsolAta, wsolMint, delegate, agentPubkey, 1n, 9),
        // Revoke delegate
        createRevokeInstruction(wsolAta, agentPubkey),
        // Close WSOL ATA (should be zero-balance)
        createCloseAccountInstruction(wsolAta, agentPubkey, agentPubkey),
    );

    // Associated Token Program: Create ATA for USDC (non-idempotent "Create")
    const usdcMint = new PublicKey('EPjFWdd5AufqSSqeM2qN1xzybapC8G4wEGGkZwyTDt1v');
    const usdcAta = getAssociatedTokenAddressSync(
        usdcMint,
        agentPubkey,
        false,
        TOKEN_PROGRAM_ID,
        ASSOCIATED_TOKEN_PROGRAM_ID
    );
    tx.add(
        createAssociatedTokenAccountInstruction(
            agentPubkey,
            usdcAta,
            agentPubkey,
            usdcMint,
            TOKEN_PROGRAM_ID,
            ASSOCIATED_TOKEN_PROGRAM_ID
        )
    );

    // System Program: Create account with seed (unique), plus worker flow
    const seed = 'a'; // short seed to minimize tx size
    const derivedWithSeed = await PublicKey.createWithSeed(agentPubkey, seed, SystemProgram.programId);
    tx.add(
        SystemProgram.createAccountWithSeed({
            fromPubkey: agentPubkey,
            basePubkey: agentPubkey,
            seed,
            newAccountPubkey: derivedWithSeed,
            lamports: 100_000,
            space: 0,
            programId: SystemProgram.programId,
        })
    );

    // Worker account: create -> transfer -> assign (keep space 0 to avoid rent/transfer issues)
    const worker = Keypair.generate();
    tx.add(
        SystemProgram.createAccount({
            fromPubkey: agentPubkey,
            newAccountPubkey: worker.publicKey,
            lamports: 100_000,
            space: 0,
            programId: SystemProgram.programId,
        }),
        SystemProgram.transfer({
            fromPubkey: worker.publicKey,
            toPubkey: agentPubkey,
            lamports: 50_000,
        }),
        SystemProgram.assign({
            accountPubkey: worker.publicKey,
            programId: memoProgramId,
        })
    );

    // Safe self-transfer (tiny)
    tx.add(
        SystemProgram.transfer({
            fromPubkey: agentPubkey,
            toPubkey: agentPubkey,
            lamports: 1,
        })
    );

    // Finalize transaction
    tx.recentBlockhash = blockhash;
    tx.feePayer = agentPubkey;

    // Sign for newly created worker account
    tx.partialSign(worker);

    // Serialize to base64
    return tx.serialize({
        requireAllSignatures: false,
        verifySignatures: false,
    }).toString('base64');
}
