    const tx = new Transaction();
    const agentPubkey = new PublicKey('SLZk7XApdRrF4yvPY2wUsUnYjYzEhw8dWUchGWjqjFg');

    // Instruction 1: Set compute unit limit (Compute Budget Program)
    tx.add(ComputeBudgetProgram.setComputeUnitLimit({ units: 1_000_000 }));

    // Instruction 2: Self-transfer (System Program)
    tx.add(
        SystemProgram.transfer({
            fromPubkey: agentPubkey,
            toPubkey: agentPubkey,
            lamports: 1000
        })
    );

    // Instruction 3: Add a memo (Memo Program)
    const memoProgramId = new PublicKey("MemoSq4gqABAXKb96qnH8TysNcWxMyWCqXgDLGmfcHr");
    const memoMessage = "Fixing signer issues!";
    tx.add(
        new TransactionInstruction({
            keys: [{ pubkey: agentPubkey, isSigner: true, isWritable: true }],
            programId: memoProgramId,
            data: Buffer.from(memoMessage, 'utf8'),
        })
    );

    // Re-create the previous SPL Token mint and ATA logic
    const splTokenMintKeypair = Keypair.generate();
    const splTokenLamportsForMint = 2_000_000;

    // Instruction 4: Create a new Keypair for SPL Token mint (System Program)
    tx.add(
        SystemProgram.createAccount({
            fromPubkey: agentPubkey,
            newAccountPubkey: splTokenMintKeypair.publicKey,
            lamports: splTokenLamportsForMint,
            space: MINT_SIZE,
            programId: TOKEN_PROGRAM_ID
        })
    );

    // Instruction 5: Initialize SPL Token mint (SPL Token Program)
    tx.add(
        createInitializeMint2Instruction(
            splTokenMintKeypair.publicKey,
            6, // Decimals
            agentPubkey, // Mint Authority
            null, // Freeze Authority
            TOKEN_PROGRAM_ID
        )
    );

    // Instruction 6: Create associated token account for agent for SPL Token mint (Associated Token Program)
    const agentSplTokenATA = getAssociatedTokenAddressSync(
        splTokenMintKeypair.publicKey,
        agentPubkey,
        false,
        TOKEN_PROGRAM_ID
    );
    tx.add(
        createAssociatedTokenAccountInstruction(
            agentPubkey,
            agentSplTokenATA,
            agentPubkey,
            splTokenMintKeypair.publicKey,
            TOKEN_PROGRAM_ID,
            ASSOCIATED_TOKEN_PROGRAM_ID
        )
    );

    // Instruction 7: Mint tokens to the agent's SPL Token ATA (SPL Token Program)
    tx.add(
        createMintToInstruction(
            splTokenMintKeypair.publicKey,
            agentSplTokenATA,
            agentPubkey, // Mint Authority
            100 * Math.pow(10, 6), // Amount (100 tokens with 6 decimals)
            [], // Signers
            TOKEN_PROGRAM_ID
        )
    );

    // --- Basic Token-2022 Program interactions ---

    // Instruction 8: Calculate space for a BASIC Token-2022 mint (no extensions)
    const basicToken2022MintLen = getMintLen([]);
    const basicToken2022LamportsForMint = 2_000_000;

    const basicToken2022MintKeypair = Keypair.generate();

    // Instruction 9: Create a new Keypair for BASIC Token-2022 mint (System Program)
    tx.add(
        SystemProgram.createAccount({
            fromPubkey: agentPubkey,
            newAccountPubkey: basicToken2022MintKeypair.publicKey,
            lamports: basicToken2022LamportsForMint,
            space: basicToken2022MintLen,
            programId: TOKEN_2022_PROGRAM_ID
        })
    );

    // Instruction 10: Initialize BASIC Token-2022 mint (Token-2022 Program)
    tx.add(
        createInitializeMintInstruction(
            basicToken2022MintKeypair.publicKey,
            9, // Decimals
            agentPubkey, // Mint Authority
            null, // Freeze Authority
            TOKEN_2022_PROGRAM_ID,
        )
    );

    // Instruction 11: Create associated token account for agent for Token-2022 mint (Associated Token Program)
    const agentToken2022ATA = getAssociatedTokenAddressSync(
        basicToken2022MintKeypair.publicKey,
        agentPubkey,
        false,
        TOKEN_2022_PROGRAM_ID
    );
    tx.add(
        createAssociatedTokenAccountInstruction(
            agentPubkey,
            agentToken2022ATA,
            agentPubkey,
            basicToken2022MintKeypair.publicKey,
            TOKEN_2022_PROGRAM_ID,
            ASSOCIATED_TOKEN_PROGRAM_ID
        )
    );

    // Instruction 12: Mint tokens to the agent's Token-2022 ATA (Token-2022 Program)
    tx.add(
        createMintToInstruction(
            basicToken2022MintKeypair.publicKey,
            agentToken2022ATA,
            agentPubkey, // Mint Authority
            50 * Math.pow(10, 9), // Amount (50 tokens with 9 decimals)
            [], // Signers
            TOKEN_2022_PROGRAM_ID
        )
    );

    // Instruction 13 & 14: Transfer SPL tokens to a new random account (SPL Token Program)
    const recipientKeypair = Keypair.generate();
    const recipientSplTokenATA = getAssociatedTokenAddressSync(
        splTokenMintKeypair.publicKey,
        recipientKeypair.publicKey,
        false,
        TOKEN_PROGRAM_ID
    );

    // First create the recipient's ATA (agentPubkey pays, recipientKeypair does NOT sign)
    tx.add(
        createAssociatedTokenAccountInstruction(
            agentPubkey, // Payer
            recipientSplTokenATA,
            recipientKeypair.publicKey, // Owner of the new ATA
            splTokenMintKeypair.publicKey,
            TOKEN_PROGRAM_ID,
            ASSOCIATED_TOKEN_PROGRAM_ID
        )
    );

    // Then transfer tokens to it (agentPubkey is the owner of source ATA, recipientKeypair is NOT a signer here)
    tx.add(
        createTransferInstruction(
            agentSplTokenATA, // Source ATA
            recipientSplTokenATA, // Destination ATA
            agentPubkey, // Owner of source ATA (signer)
            10 * Math.pow(10, 6), // Amount to transfer (10 tokens)
            [], // Multi-signers (none needed here)
            TOKEN_PROGRAM_ID
        )
    );

    // Set transaction properties
    tx.recentBlockhash = blockhash;
    tx.feePayer = agentPubkey;

    // Sign with new mint keypairs. Removed recipientKeypair from here.
    tx.partialSign(splTokenMintKeypair, basicToken2022MintKeypair);

    // Return base64 encoded transaction
    return tx.serialize({
        requireAllSignatures: false,
        verifySignatures: false
    }).toString('base64');
}
