    const memoProgramId = new PublicKey('MemoSq4gqABAXKb96qnH8TysNcWxMyWCqXgDLGmfcHr');
    tx.add({
        keys: [{ pubkey: agentPubkey, isSigner: true, isWritable: true }],
        programId: memoProgramId,
        data: Buffer.from('Reducing tx size!', 'utf8')
    });

    // Instruction 2: Create a new account (SystemProgram.createAccount)
    // Removed SystemProgram.assign as it's redundant when programId is SystemProgram.programId
    const newAccount = Keypair.generate();
    tx.add(
        SystemProgram.createAccount({
            fromPubkey: agentPubkey,
            newAccountPubkey: newAccount.publicKey,
            lamports: 1000000,
            space: 0,
            programId: SystemProgram.programId
        })
    );

    // Instructions 3 & 4: Create a new mint (SPL Token Program - TokenkegQfeZyiNwAJbNbGKPFXCWuBvf9Ss623VQ5DA)
    const mintAccount = Keypair.generate();
    const tokenProgramId = TOKEN_PROGRAM_ID; // TokenkegQfeZyiNwAJbNbGKPFXCWuBvf9Ss623VQ5DA
    const rentExemptionAmount = 1_461_600;

    tx.add(
        SystemProgram.createAccount({
            fromPubkey: agentPubkey,
            newAccountPubkey: mintAccount.publicKey,
            lamports: rentExemptionAmount,
            space: MINT_SIZE,
            programId: tokenProgramId }),
        createInitializeMintInstruction(
            mintAccount.publicKey,
            9,
            agentPubkey,
            agentPubkey,
            tokenProgramId
        )
    );

    // Instruction 5: Create Associated Token Account for agentPubkey (Associated Token Program)
    const associatedTokenProgramId = new PublicKey('ATokenGPvbdGVxr1b2hvZbsiqW5xWH25efTNsLJA8knL');
    const associatedTokenAccount = getAssociatedTokenAddressSync(
        mintAccount.publicKey,
        agentPubkey,
        false,
        tokenProgramId,
        associatedTokenProgramId
    );

    tx.add(
        createAssociatedTokenAccountInstruction(
            agentPubkey,
            associatedTokenAccount,
            agentPubkey,
            mintAccount.publicKey,
            tokenProgramId,
            associatedTokenProgramId
        )
    );

    // Instruction 6: Mint tokens to the Associated Token Account (SPL Token Program)
    tx.add(
        createMintToInstruction(
            mintAccount.publicKey,
            associatedTokenAccount,
            agentPubkey,
            1000000000, // Amount (1 token with 9 decimals)
            [],
            tokenProgramId
        )
    );

    // Token-2022 (TokenzQdBNbLqP5VEhdkAS6EPFLC1PHnBqCXEpPxuEb)
    const token2022MintAccount = Keypair.generate();
    const token2022ProgramId = TOKEN_2022_PROGRAM_ID;

    // 7. Calculate space and create account for Token-2022 mint with TransferFeeConfig
    const extensions = [ExtensionType.TransferFeeConfig];
    const mintLen = getMintLen(extensions);
    const token2022RentExemption = 1_461_600;

    tx.add(
        SystemProgram.createAccount({
            fromPubkey: agentPubkey,
            newAccountPubkey: token2022MintAccount.publicKey,
            lamports: token2022RentExemption,
            space: mintLen,
            programId: token2022ProgramId })
    );

    // 8. Initialize TransferFeeConfig extension
    tx.add(
        createInitializeTransferFeeConfigInstruction(
            token2022MintAccount.publicKey, // mint
            agentPubkey,                    // transferFeeConfigAuthority
            agentPubkey,                    // withdrawWithheldAuthority
            100,                            // transferFeeBasisPoints (0.01%)
            BigInt(1000),                   // maximumFee
            token2022ProgramId              // programId
        )
    );

    // 9. Initialize the Token-2022 mint
    tx.add(
        createInitializeMint2022Instruction(
            token2022MintAccount.publicKey, // Mint Account
            6,                              // Decimals
            agentPubkey,                    // Mint Authority
            agentPubkey,                    // Freeze Authority (optional, use null if not needed)
            token2022ProgramId               // Token Program ID (Token-2022)
        )
    );

    // 10. Create Associated Token Account for Token-2022 mint for agentPubkey
    const associatedTokenAccount2022 = getAssociatedTokenAddressSync(
        token2022MintAccount.publicKey,
        agentPubkey,
        false,
        token2022ProgramId, // Use Token-2022 program ID for ATA
        associatedTokenProgramId // Still Associated Token Program ID
    );

    tx.add(
        createAssociatedTokenAccount2022Instruction(
            agentPubkey,            // payer
            associatedTokenAccount2022, // associatedToken
            agentPubkey,            // owner
            token2022MintAccount.publicKey,  // mint
            token2022ProgramId,         // programId (Token-2022)
            associatedTokenProgramId // associatedTokenProgramId
        )
    );

    // 11. Mint Token-2022 tokens to the new ATA
    tx.add(
        createMintTo2022Instruction(
            token2022MintAccount.publicKey,  // mint
            associatedTokenAccount2022,      // destination
            agentPubkey,                     // authority
            1000000000000000n,               // amount (1,000,000 with 6 decimals) - using BigInt for large numbers
            [],                              // multiSigners
            token2022ProgramId               // programId (Token-2022)
        )
    );

    // Set transaction properties
    tx.recentBlockhash = blockhash;
    tx.feePayer = agentPubkey;

    // Sign the transaction with all new account keypairs
    tx.partialSign(newAccount, mintAccount, token2022MintAccount);

    // Return base64 encoded transaction
    return tx.serialize({
        requireAllSignatures: false,
        verifySignatures: false
    }).toString('base64');
}

