import { PublicKey, Transaction } from '@solana/web3.js';
import { NATIVE_MINT } from '@solana/spl-token';

export async function executeSkill(blockhash: string): Promise<string> {
    const connection = new('http://localhost:8899');
    const agentPubkey = new PublicKey('7PwPYHreVUL7p8XF7trW3g8iScS9hfin11oAf6dNVJEA');

    try {
        // Go back to what works - SOL to RAY with no DEX restrictions
        const quoteUrl = 'https://quote-api.jup.ag/v6/quote?' + new URLSearchParams({
            inputMint: NATIVE_MINT.toString(), // SOL
            outputMint: '4k3Dyjzvzp8eMZWUXbBCjEvwSkkk59S5iCNLY3QrkX6R', // RAY
            amount: '2000000', // 0.002 SOL (slightly larger to potentially trigger different routing)
            slippageBps: '1000', // 10% slippage
            onlyDirectRoutes: 'false', // Allow routing to discover more programs
            maxAccounts: '20' // Limit accounts to keep transaction size manageable
        });

        const quoteResponse = await fetch(quoteUrl);
        const quote = await quoteResponse.json();

        if (quote.error || !quote.outAmount) {
            throw new Error(`Quote failed: ${JSON.stringify(quote)}`);
        }

        // Get swap transaction
        const swapBody = {
            quoteResponse: quote,
            userPublicKey: agentPubkey.toString(),
            wrapAndUnwrapSol: true,
            asLegacyTransaction: true,
            useSharedAccounts: false
        };

        const swapResponse = await fetch('https://quote-api.jup.ag/v6/swap', {
            method: 'POST',
            headers: { 
                'Content-Type': 'application/json'
            },
            body: JSON.stringify(swapBody)
        });

        const swapResult = await swapResponse.json();

        if (!swapResult.swapTransaction) {
            throw new Error(`Swap failed: ${JSON.stringify(swapResult)}`);
        }

        // Handle as legacy transaction
        const txBuffer = Buffer.from(swapResult.swapTransaction, 'base64');
        const swapTransaction = Transaction.from(txBuffer);
        swapTransaction.recentBlockhash = blockhash;

        return swapTransaction.serialize({ requireAllSignatures: false }).toString('base64');

    } catch (error) {
        throw new Error(`Jupiter SOL->RAY swap failed: ${error.message}`);
    }
}

