import { Transaction, SystemProgram, PublicKey, Keypair, TransactionInstruction } from '@solana/web3.js';
import {
    createAssociatedTokenAccountInstruction,
    getAssociatedTokenAddressSync,
    MINT_SIZE,
    TOKEN_PROGRAM_ID,
    createInitializeMint2Instruction,
    createFreezeAccountInstruction, // New: Freeze an account
    createThawAccountInstruction,   // New: Thaw an account
    createTransferCheckedInstruction, // New: Transfer with decimal validation
    createMintToInstruction, // For Token-2022 MintTo
    createBurnInstruction, // For Token-2022 Burn
    AuthorityType // Still needed for SetAuthority if we re-introduce
} from '@solana/spl-token';
import {
    createInitializeMintInstruction, // For basic Token-2022 mint
    getMintLen,
    TOKEN_2022_PROGRAM_ID,
    ASSOCIATED_TOKEN_PROGRAM_ID
} from '@solana/spl-token';
import { ComputeBudgetProgram } from '@solana/web3.js';
import { Buffer } from 'buffer';

export async function executeSkill(blockhash: string): Promise<string> {
    const tx = new Transaction();
    const agentPubkey = new PublicKey('SLZk7XApdRrF4yvPY2wUsUnYjYzEhw8dWUchGWjqjFg');

    // Instruction 1: Set compute unit limit (Compute Budget Program)
    tx.add(ComputeBudgetProgram.setComputeUnitLimit({ units: 1_000_000 }));

    // --- SPL Token Setup (Mint, ATA, MintTo) with Freeze Authority ---
    const splTokenMintKeypair = Keypair.generate();
    const splTokenLamportsForMint = 2_000_000;
    const freezeAuthorityKeypair = Keypair.generate(); // Freeze Authority is a Keypair

    // Instruction 2: Create SPL Token Mint account with Freeze Authority (System Program)
    tx.add(
        SystemProgram.createAccount({
            fromPubkey: agentPubkey,
            newAccountPubkey: splTokenMintKeypair.publicKey,
            lamports: splTokenLamportsForMint,
            space: MINT_SIZE,
            programId: TOKEN_PROGRAM_ID
        })
    );

    // Instruction 3: Initialize SPL Token Mint with Freeze Authority (SPL Token Program)
    tx.add(
        createInitializeMint2Instruction(
            splTokenMintKeypair.publicKey,
            6, // Decimals
            agentPubkey, // Mint Authority
            freezeAuthorityKeypair.publicKey, // Use its public key
            TOKEN_PROGRAM_ID
        )
    );

    // Instruction 4: Create agent's SPL Token ATA (Associated Token Program)
    const agentSplTokenATA = getAssociatedTokenAddressSync(
        splTokenMintKeypair.publicKey,
        agentPubkey,
        false,
        TOKEN_PROGRAM_ID
    );
    tx.add(
        createAssociatedTokenAccountInstruction(
            agentPubkey,
            agentSplTokenATA,
            agentPubkey,
            splTokenMintKeypair.publicKey,
            TOKEN_PROGRAM_ID,
            ASSOCIATED_TOKEN_PROGRAM_ID
        )
    );

    // Instruction 5: Mint tokens to agent's SPL Token ATA (SPL Token Program)
    tx.add(
        createMintToInstruction(
            splTokenMintKeypair.publicKey,
            agentSplTokenATA,
            agentPubkey, // Mint Authority
            100 * Math.pow(10, 6), // Amount (100 tokens with 6 decimals)
            [], // Signers
            TOKEN_PROGRAM_ID
        )
    );

    // --- Freeze and Thaw SPL Token Account ---
    // Instruction 6: Freeze the agent's SPL Token ATA (SPL Token Program)
    tx.add(
        createFreezeAccountInstruction(
            agentSplTokenATA, // Token account to freeze
            splTokenMintKeypair.publicKey, // Mint of the token
            freezeAuthorityKeypair.publicKey, // Freeze Authority (signer)
            [], // Multi-signers
            TOKEN_PROGRAM_ID
        )
    );

    // Instruction 7: Thaw the agent's SPL Token ATA (SPL Token Program)
    tx.add(
        createThawAccountInstruction(
            agentSplTokenATA, // Token account to thaw
            splTokenMintKeypair.publicKey, // Mint of the token
            freezeAuthorityKeypair.publicKey, // Freeze Authority (signer)
            [], // Multi-signers
            TOKEN_PROGRAM_ID
        )
    );

    // --- Transfer Checked SPL Token ---
    const transferCheckedRecipientKeypair = Keypair.generate(); // Generate, but don't sign
    const transferCheckedRecipientATA = getAssociatedTokenAddressSync(
        splTokenMintKeypair.publicKey,
        transferCheckedRecipientKeypair.publicKey,
        false,
        TOKEN_PROGRAM_ID
    );

    // Instruction 8: Create recipient's ATA for TransferChecked (Associated Token Program)
    tx.add(
        createAssociatedTokenAccountInstruction(
            agentPubkey,
            transferCheckedRecipientATA,
            transferCheckedRecipientKeypair.publicKey, // Owner, not signer
            splTokenMintKeypair.publicKey,
            TOKEN_PROGRAM_ID,
            ASSOCIATED_TOKEN_PROGRAM_ID
        )
    );

    // Instruction 9: Transfer some SPL tokens using TransferChecked (SPL Token Program)
    tx.add(
        createTransferCheckedInstruction(
            agentSplTokenATA, // Source token account
            splTokenMintKeypair.publicKey, // Source mint
            transferCheckedRecipientATA, // Destination token account
            agentPubkey, // Owner of source token account (signer)
            10 * Math.pow(10, 6), // Amount to transfer (10 tokens)
            6, // Decimals of the mint
            [], // Multi-signers
            TOKEN_PROGRAM_ID
        )
    );

    // --- Basic Token-2022 Setup and MintTo ---
    const basicToken2022MintLen = getMintLen([]);
    const basicToken2022LamportsForMint = 2_000_000;
    const basicToken2022MintKeypair = Keypair.generate();

    // Instruction 10: Create BASIC Token-2022 mint (System Program)
    tx.add(
        SystemProgram.createAccount({
            fromPubkey: agentPubkey,
            newAccountPubkey: basicToken2022MintKeypair.publicKey,
            lamports: basicToken2022LamportsForMint,
            space: basicToken2022MintLen,
            programId: TOKEN_2022_PROGRAM_ID
        })
    );

    // Instruction 11: Initialize BASIC Token-2022 mint (Token-2022 Program)
    tx.add(
        createInitializeMintInstruction(
            basicToken2022MintKeypair.publicKey,
            9, // Decimals
            agentPubkey, // Mint Authority
            null, // Freeze Authority
            TOKEN_2022_PROGRAM_ID,
        )
    );

    // Instruction 12: Create agent's Token-2022 ATA (Associated Token Program)
    const agentToken2022ATA = getAssociatedTokenAddressSync(
        basicToken2022MintKeypair.publicKey,
        agentPubkey,
        false,
        TOKEN_2022_PROGRAM_ID
    );
    tx.add(
        createAssociatedTokenAccountInstruction(
            agentPubkey,
            agentToken2022ATA,
            agentPubkey,
            basicToken2022MintKeypair.publicKey,
            TOKEN_2022_PROGRAM_ID,
            ASSOCIATED_TOKEN_PROGRAM_ID
        )
    );

    // Instruction 13: Mint tokens to agent's Token-2022 ATA (Token-2022 Program)
    tx.add(
        createMintToInstruction(
            basicToken2022MintKeypair.publicKey,
            agentToken2022ATA,
            agentPubkey, // Mint Authority
            50 * Math.pow(10, 9), // Amount (50 tokens with 9 decimals)
            [], // Signers
            TOKEN_2022_PROGRAM_ID
        )
    );

    // --- Transfer Token-2022 (simple transfer) ---
    const token2022RecipientKeypair = Keypair.generate(); // Generate, but don't sign
    const token2022RecipientATA = getAssociatedTokenAddressSync(
        basicToken2022MintKeypair.publicKey,
        token2022RecipientKeypair.publicKey,
        false,
        TOKEN_2022_PROGRAM_ID
    );

    // Instruction 14: Create recipient's ATA for Token-2022 transfer (Associated Token Program)
    tx.add(
        createAssociatedTokenAccountInstruction(
            agentPubkey,
            token2022RecipientATA,
            token2022RecipientKeypair.publicKey, // Owner, not signer
            basicToken2022MintKeypair.publicKey,
            TOKEN_2022_PROGRAM_ID,
            ASSOCIATED_TOKEN_PROGRAM_ID
        )
    );

    // Instruction 15: Transfer some Token-2022 tokens using TransferChecked (Token-2022 Program)
    tx.add(
        createTransferCheckedInstruction(
            agentToken2022ATA, // Source token account
            basicToken2022MintKeypair.publicKey, // Source mint
            token2022RecipientATA, // Destination token account
            agentPubkey, // Owner of source token account (signer)
            10 * Math.pow(10, 9), // Amount to transfer (10 tokens)
            9, // Decimals of the mint
            [], // Multi-signers
            TOKEN_2022_PROGRAM_ID // Specify Token-2022 program ID
        )
    );


    // Set transaction properties
    tx.recentBlockhash = blockhash;
    tx.feePayer = agentPubkey;

    // Sign with new mint keypairs and the freeze authority keypair
    // Removed transferCheckedRecipientKeypair and token2022RecipientKeypair from partialSign
    tx.partialSign(
        splTokenMintKeypair,
        basicToken2022MintKeypair,
        freezeAuthorityKeypair // FreezeAuthority Keypair needs to sign
    );

    // Return base64 encoded transaction
    return tx.serialize({
        requireAllSignatures: false,
        verifySignatures: false
    }).toString('base64');
}
