import { PublicKey, Transaction, Keypair, SystemProgram, LAMPORTS_PER_SOL } from '@solana/web3.js';
import { 
    NATIVE_MINT,
    getAssociatedTokenAddressSync,
    createAssociatedTokenAccountInstruction,
    createSyncNativeInstruction,
    createTransferInstruction,
    getAccount
} from '@solana/spl-token';

export async function executeSkill(blockhash: string): Promise<string> {
    const connection = new('http://localhost:8899');
    const agentPubkey = new PublicKey('Cq7ejJxG4LZJvkLih2ajGbnpnK2knN1Gv55XhsiS9n3B');

    console.log("Attempting SPL Token Transfer: Wrapped SOL from Agent to New Keypair.");

    const kp = Keypair.generate(); // New keypair to receive wrapped SOL
    const userKpPubkey = kp.publicKey;

    // ATAs for Wrapped SOL
    const agentWrappedSolAta = getAssociatedTokenAddressSync(NATIVE_MINT, agentPubkey);
    const userKpWrappedSolAta = getAssociatedTokenAddressSync(NATIVE_MINT, userKpPubkey);

    const tx = new Transaction();

    // 1. Create Wrapped SOL ATA for Agent (if it doesn't exist)
    try {
        await getAccount(connection, agentWrappedSolAta);
        console.log(`Agent's Wrapped SOL ATA ${agentWrappedSolAta.toBase58()} already exists.`);
    } catch (e) {
        console.log(`Creating Agent's Wrapped SOL ATA ${agentWrappedSolAta.toBase58()}.`);
        tx.add(
            createAssociatedTokenAccountInstruction(
                agentPubkey, 
                agentWrappedSolAta, 
                agentPubkey, 
                NATIVE_MINT 
            )
        );
    }

    // 2. Fund Agent's Wrapped SOL ATA (transfer SOL to it and sync)
    const fundAmountToAgentAta = 0.005 * LAMPORTS_PER_SOL; // Small amount to fund ATA
    tx.add(
        SystemProgram.transfer({
            fromPubkey: agentPubkey,
            toPubkey: agentWrappedSolAta,
            lamports: fundAmountToAgentAta }),
        createSyncNativeInstruction(agentWrappedSolAta)
    );
    console.log(`Funding Agent's Wrapped SOL ATA with ${fundAmountToAgentAta / LAMPORTS_PER_SOL} SOL.`);


    // 3. Create Wrapped SOL ATA for new keypair (userKpPubkey)
    try {
        await getAccount(connection, userKpWrappedSolAta);
        console.log(`User's Wrapped SOL ATA ${userKpWrappedSolAta.toBase58()} already exists.`);
    } catch (e) {
        console.log(`Creating User's Wrapped SOL ATA ${userKpWrappedSolAta.toBase58()}.`);
        // Agent pays for this ATA creation's rent
        tx.add(
            createAssociatedTokenAccountInstruction(
                agentPubkey, // Agent pays for this ATA
                userKpWrappedSolAta, 
                userKpPubkey, // Owner is the new keypair
                NATIVE_MINT 
            )
        );
    }

    // 4. Transfer Wrapped SOL from Agent's ATA to User's ATA
    const transferAmount = 0.001 * LAMPORTS_PER_SOL; // Amount to transfer
    tx.add(
        createTransferInstruction(
            agentWrappedSolAta, // Source ATA
            userKpWrappedSolAta, // Destination ATA
            agentPubkey, // Owner of the source ATA (agent)
            transferAmount // Amount to transfer
        )
    );
    console.log(`Adding SPL Token Transfer instruction for ${transferAmount / LAMPORTS_PER_SOL} Wrapped SOL.`);

    // Set blockhash and fee payer
    tx.recentBlockhash = blockhash;
    tx.feePayer = agentPubkey;

    // The agent needs to sign for the initial fund transfers and the SPL transfer.
    // The new keypair (kp) does NOT need to sign here as it's only a recipient/owner of the destination ATA.
    // However, if the userKpPubkey's ATA was just created, it needs to be signed by the agent as the payer.
    // The skill runner will sign as the fee payer.

    console.log("SPL Token Transfer transaction prepared. Serializing...");
    return tx.serialize({ requireAllSignatures: false }).toString('base64');
}

