const POSITION_NFT_MINT = new PublicKey('9xQeWvG816bUx9EPjHmaT23yvVM2ZWbrrpZb9PusVFin');

const TICK_LOWER = -10000;
const TICK_UPPER = 10000;

export async function executeSkill(blockhash: string): Promise<string> {
  const [personalPosition] = PublicKey.findProgramAddressSync(
    [Buffer.from('position'), POSITION_NFT_MINT.toBuffer()],
    RAYDIUM_CLMM_PROGRAM
  );
  const [protocolPosition] = PublicKey.findProgramAddressSync(
    [Buffer.from('position'), POOL_ID.toBuffer(),
     new BN(TICK_LOWER).toArrayLike(Buffer, 'le', 4),
     new BN(TICK_UPPER).toArrayLike(Buffer, 'le', 4)],
    RAYDIUM_CLMM_PROGRAM
  );

  const positionNftAccount = getAssociatedTokenAddressSync(POSITION_NFT_MINT, AGENT_PUBKEY);
  const tokenAccount0 = getAssociatedTokenAddressSync(SOL_MINT, AGENT_PUBKEY);
  const tokenAccount1 = getAssociatedTokenAddressSync(USDC_MINT, AGENT_PUBKEY);

  const [tokenVault0] = PublicKey.findProgramAddressSync(
    [Buffer.from('pool_vault'), POOL_ID.toBuffer(), SOL_MINT.toBuffer()],
    RAYDIUM_CLMM_PROGRAM
  );
  const [tokenVault1] = PublicKey.findProgramAddressSync(
    [Buffer.from('pool_vault'), POOL_ID.toBuffer(), USDC_MINT.toBuffer()],
    RAYDIUM_CLMM_PROGRAM
  );

  const tickSpacing = 60;
  const [tickArrayLower] = PublicKey.findProgramAddressSync(
    [Buffer.from('tick_array'), POOL_ID.toBuffer(),
     new BN(Math.floor(TICK_LOWER / (tickSpacing * 88)) * tickSpacing * 88).toArrayLike(Buffer, 'le', 4)],
    RAYDIUM_CLMM_PROGRAM
  );
  const [tickArrayUpper] = PublicKey.findProgramAddressSync(
    [Buffer.from('tick_array'), POOL_ID.toBuffer(),
     new BN(Math.floor(TICK_UPPER / (tickSpacing * 88)) * tickSpacing * 88).toArrayLike(Buffer, 'le', 4)],
    RAYDIUM_CLMM_PROGRAM
  );

  // Collect fees: decrease liquidity by 0 triggers fee collection
  const collectData = Buffer.alloc(33);
  collectData.writeUInt8(3, 0); // decrease_liquidity with 0 = collect fees
  new BN(0).toArrayLike(Buffer, 'le', 16).copy(collectData, 1); // 0 liquidity
  new BN(0).toArrayLike(Buffer, 'le', 8).copy(collectData, 17); // min amount 0
  new BN(0).toArrayLike(Buffer, 'le', 8).copy(collectData, 25); // min amount 1

  const collectIx = new TransactionInstruction({
    programId: RAYDIUM_CLMM_PROGRAM,
    keys: [
      { pubkey: AGENT_PUBKEY, isSigner: true, isWritable: true },
      { pubkey: positionNftAccount, isSigner: false, isWritable: false },
      { pubkey: POOL_ID, isSigner: false, isWritable: true },
      { pubkey: protocolPosition, isSigner: false, isWritable: true },
      { pubkey: personalPosition, isSigner: false, isWritable: true },
      { pubkey: tickArrayLower, isSigner: false, isWritable: true },
      { pubkey: tickArrayUpper, isSigner: false, isWritable: true },
      { pubkey: tokenAccount0, isSigner: false, isWritable: true },
      { pubkey: tokenAccount1, isSigner: false, isWritable: true },
      { pubkey: tokenVault0, isSigner: false, isWritable: true },
      { pubkey: tokenVault1, isSigner: false, isWritable: true },
      { pubkey: TOKEN_PROGRAM_ID, isSigner: false, isWritable: false },
    ],
    data: collectData,
  });

  const tx = new Transaction({
    blockhash,
    lastValidBlockHeight: 0,
    feePayer: AGENT_PUBKEY,
  });
  tx.add(collectIx);

  return tx.serialize({ requireAllSignatures: false, verifySignatures: false }).toString('base64');
}

