    tx.add({
        programId: MEMO_PROGRAM_ID,
        keys: [
            { pubkey: agentPubkey, isSigner: true, isWritable: false },
            { pubkey: account1.publicKey, isSigner: false, isWritable: false },
            { pubkey: account2.publicKey, isSigner: false, isWritable: false }
        ],
        data: Buffer.from("Config exploration!", "utf8")
    });

    tx.add({
        programId: MEMO_PROGRAM_ID,
