    });

    tx.add({
        programId: MEMO_PROGRAM_ID,
        keys: [
            { pubkey: agentPubkey, isSigner: false, isWritable: false }
        ],
        data: Buffer.from("Non-signer memo!", "utf8")
    });

    // Transfer
    tx.add(
        SystemProgram.transfer({
            fromPubkey: agentPubkey,
            toPubkey: account2.publicKey,
            lamports: 15000
        })
    );

