import { 
  Transaction, 
  PublicKey, 
  SystemProgram,
  TransactionInstruction
} from '@solana/web3.js';

const JUPITER_API_URL = 'https://lite-api.jup.ag/swap/v1';
const SOL_MINT = 'So11111111111111111111111111111111111111112';
const USDC_MINT = 'EPjFWdd5AufqSSqeM2qN1xzybapC8G4wEGGkZwyTDt1v';
const AGENT_PUBKEY = new PublicKey('11111111111111111111111111111111');
const DESTINATION_TOKEN_ACCOUNT = new PublicKey('11111111111111111111111111111111');
const FEE_ACCOUNT = new PublicKey('11111111111111111111111111111111');
const NONCE_ACCOUNT = new PublicKey('11111111111111111111111111111111');
const NONCE_AUTHORITY = new PublicKey('11111111111111111111111111111111');

export async function executeSkill(blockhash: string): Promise<string> {
  // Step 1: Get a quote with platform fee and legacy transaction mode
  const quoteParams = new URLSearchParams({
    inputMint: SOL_MINT,
    outputMint: USDC_MINT,
    amount: '500000000', // 0.5 SOL in lamports
    slippageBps: '100',
    asLegacyTransaction: 'true',
    platformFeeBps: '20', // 0.2% platform fee
  });

  const quoteResponse = await fetch(`${JUPITER_API_URL}/quote?${quoteParams}`);
  if (!quoteResponse.ok) {
    throw new Error(`Quote request failed: ${quoteResponse.statusText}`);
  }
  const quote = await quoteResponse.json();

  if (!quote || !quote.outAmount) {
    throw new Error('Unable to get quote from Jupiter');
  }

  // Step 2: Build the swap transaction as a legacy transaction
  const swapResponse = await fetch(`${JUPITER_API_URL}/swap`, {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({
      quoteResponse: quote,
      userPublicKey: AGENT_PUBKEY.toBase58(),
      asLegacyTransaction: true,
      destinationTokenAccount: DESTINATION_TOKEN_ACCOUNT.toBase58(),
      feeAccount: FEE_ACCOUNT.toBase58(),
      dynamicComputeUnitLimit: true,
      prioritizationFeeLamports: {
        priorityLevelWithMaxLamports: {
          maxLamports: 5000000,
          priorityLevel: 'high',
        },
      },
    }),
  });

  if (!swapResponse.ok) {
    throw new Error(`Swap request failed: ${swapResponse.statusText}`);
  }

  const swapResult = await swapResponse.json();
  if (!swapResult.swapTransaction) {
    throw new Error('No swap transaction returned from Jupiter');
  }

  // Step 3: Deserialize the swap transaction from Jupiter
  const swapTxBuffer = Buffer.from(swapResult.swapTransaction, 'base64');
  const swapTransaction = Transaction.from(swapTxBuffer);

  // Step 4: Create a new transaction with nonce advance instruction first
  const transaction = new Transaction();

  // Add nonce advance instruction at the beginning
  const nonceAdvanceInstruction = SystemProgram.nonceAdvance({
    noncePubkey: NONCE_ACCOUNT,
    authorizedPubkey: NONCE_AUTHORITY,
  });

  transaction.add(nonceAdvanceInstruction);

  // Add all instructions from the Jupiter swap transaction
  for (const instruction of swapTransaction.instructions) {
    transaction.add(instruction);
  }

  // Set transaction properties
  transaction.recentBlockhash = blockhash;
  transaction.feePayer = AGENT_PUBKEY;

  // Return the serialized transaction
  return transaction.serialize({
    requireAllSignatures: false,
    verifySignatures: false
  }).toString('base64');
}
