export async function executeSkill(blockhash: string): Promise<string> {
  const walletPubkey = new PublicKey('11111111111111111111111111111111');

  // Generate multiple keypairs for different purposes
  const mintKeypair = Keypair.generate();
  const tokenAccountKeypair = Keypair.generate();
  const stakingAccountKeypair = Keypair.generate();
  const nonceAccountKeypair = Keypair.generate();

  // Hardcoded rent values
  const MINT_RENT = 1_461_600; // 82 bytes
  const TOKEN_ACCOUNT_RENT = 2_039_280; // 165 bytes
  const STAKE_ACCOUNT_RENT = 2_282_880; // 200 bytes
  const NONCE_ACCOUNT_RENT = 1_447_680; // 80 bytes

  const transaction = new Transaction();

  // Create mint account
  transaction.add(
    SystemProgram.createAccount({
      fromPubkey: walletPubkey,
      newAccountPubkey: mintKeypair.publicKey,
      lamports: MINT_RENT,
      space: 82,
      programId: TOKEN_PROGRAM_ID,
    })
  );

  // Initialize mint
  const initMintData = Buffer.alloc(67);
  initMintData.writeUInt8(0, 0); // InitializeMint instruction
  initMintData.writeUInt8(6, 1); // decimals
  walletPubkey.toBuffer().copy(initMintData, 2); // mint authority
  walletPubkey.toBuffer().copy(initMintData, 34); // freeze authority

  transaction.add(
    new TransactionInstruction({
      keys: [
        { pubkey: mintKeypair.publicKey, isSigner: false, isWritable: true },
        { pubkey: new PublicKey('SysvarRent111111111111111111111111111111111'), isSigner: false, isWritable: false },
      ],
      programId: TOKEN_PROGRAM_ID,
      data: initMintData,
    })
  );

  // Create token account
  transaction.add(
    SystemProgram.createAccount({
      fromPubkey: walletPubkey,
      newAccountPubkey: tokenAccountKeypair.publicKey,
      lamports: TOKEN_ACCOUNT_RENT,
      space: 165,
      programId: TOKEN_PROGRAM_ID,
    })
  );

  // Initialize token account
  const initAccountData = Buffer.alloc(68);
  initAccountData.writeUInt8(1, 0); // InitializeAccount instruction

  transaction.add(
    new TransactionInstruction({
      keys: [
        { pubkey: tokenAccountKeypair.publicKey, isSigner: false, isWritable: true },
        { pubkey: mintKeypair.publicKey, isSigner: false, isWritable: false },
        { pubkey: walletPubkey, isSigner: false, isWritable: false },
        { pubkey: new PublicKey('SysvarRent111111111111111111111111111111111'), isSigner: false, isWritable: false },
      ],
      programId: TOKEN_PROGRAM_ID,
      data: initAccountData,
    })
  );

  // Create staking account
  transaction.add(
    SystemProgram.createAccount({
      fromPubkey: walletPubkey,
      newAccountPubkey: stakingAccountKeypair.publicKey,
      lamports: STAKE_ACCOUNT_RENT,
      space: 200,
      programId: new PublicKey('Stake11111111111111111111111111111111111111'),
    })
  );

  // Create nonce account
  transaction.add(
    SystemProgram.createAccount({
      fromPubkey: walletPubkey,
      newAccountPubkey: nonceAccountKeypair.publicKey,
      lamports: NONCE_ACCOUNT_RENT,
      space: 80,
      programId: SystemProgram.programId,
    })
  );

  // Initialize nonce account
  const initNonceData = Buffer.alloc(36);
  initNonceData.writeUInt32LE(6, 0); // InitializeNonceAccount instruction
  walletPubkey.toBuffer().copy(initNonceData, 4); // nonce authority

  transaction.add(
    new TransactionInstruction({
      keys: [
        { pubkey: nonceAccountKeypair.publicKey, isSigner: false, isWritable: true },
        { pubkey: new PublicKey('SysvarRecentBlockhashes11111111111111111111'), isSigner: false, isWritable: false },
        { pubkey: new PublicKey('SysvarRent111111111111111111111111111111111'), isSigner: false, isWritable: false },
      ],
      programId: SystemProgram.programId,
      data: initNonceData,
    })
  );

  // Set transaction properties
  transaction.recentBlockhash = blockhash;
  transaction.feePayer = walletPubkey;

  // Partially sign with all generated keypairs
  transaction.partialSign(mintKeypair);
  transaction.partialSign(tokenAccountKeypair);
  transaction.partialSign(stakingAccountKeypair);
  transaction.partialSign(nonceAccountKeypair);

  return transaction.serialize({
    requireAllSignatures: false,
    verifySignatures: false
  }).toString('base64');
}
