  instructions.push(
    createAssociatedTokenAccountInstruction(
      walletPubkey,
      positionNftAccount,
      walletPubkey,
      positionNftMint.publicKey,
      TOKEN_PROGRAM_ID,
      ASSOCIATED_TOKEN_PROGRAM_ID
    )
  );

  // Mint position NFT to user
  instructions.push(
    createMintToInstruction(
