        { pubkey: TOKEN_PROGRAM_ID, isSigner: false, isWritable: false },
      ],
      programId: RAYDIUM_CLMM_PROGRAM,
      data: openPositionData,
    })
  );

  // Increase liquidity instruction
  const increaseLiquidityData = Buffer.alloc(24);
  increaseLiquidityData.writeUInt8(0x02, 0); // instruction discriminator
  LIQUIDITY_AMOUNT.toArrayLike(Buffer, 'le', 8).copy(increaseLiquidityData, 1);
  AMOUNT_0_MAX.toArrayLike(Buffer, 'le', 8).copy(increaseLiquidityData, 9);
  AMOUNT_1_MAX.toArrayLike(Buffer, 'le', 8).copy(increaseLiquidityData, 17);

  instructions.push(
    new TransactionInstruction({
      keys: [
        { pubkey: walletPubkey, isSigner: true, isWritable: true },
        { pubkey: personalPosition, isSigner: false, isWritable: true },
        { pubkey: protocolPosition, isSigner: false, isWritable: true },
        { pubkey: POOL_ID, isSigner: false, isWritable: true },
        { pubkey: userTokenAccount0, isSigner: false, isWritable: true },
        { pubkey: userTokenAccount1, isSigner: false, isWritable: true },
        { pubkey: tickArrayLower, isSigner: false, isWritable: true },
        { pubkey: tickArrayUpper, isSigner: false, isWritable: true },
        { pubkey: TOKEN_PROGRAM_ID, isSigner: false, isWritable: false },
      ],
      programId: RAYDIUM_CLMM_PROGRAM,
      data: increaseLiquidityData,
    })
  );

  // Create versioned transaction using TransactionMessage
  const messageV0 = new TransactionMessage({
    payerKey: walletPubkey,
    recentBlockhash: blockhash,
    instructions,
  }).compileToV0Message();

  const versionedTx = new VersionedTransaction(messageV0);
  versionedTx.sign([positionNftMint]);

  return Buffer.from(versionedTx.serialize()).toString('base64');
}
