  const userSolAta = getAssociatedTokenAddressSync(SOL_MINT, walletPubkey);

  // Generate DCA order account (deterministic PDA)
  const [dcaOrderPda] = PublicKey.findProgramAddressSync(
    [
      Buffer.from('dca_order'),
      walletPubkey.toBuffer(),
      USDC_MINT.toBuffer(),
      SOL_MINT.toBuffer(),
      Buffer.from([0]), // order index
    ],
    JUPITER_DCA_PROGRAM_ID
  );

  // Create DCA order instruction data
  const orderAmount = 100_000_000; // 100 USDC (6 decimals)
  const numOrders = 10;
  const cycleFrequency = 86400; // 1 day in seconds

  const instructionData = Buffer.alloc(32);
  let offset = 0;

  // Instruction discriminator for create_dca_order
  instructionData.writeUInt8(0, offset); // instruction index
  offset += 1;

  // Order parameters
  instructionData.writeBigUInt64LE(BigInt(orderAmount), offset);
  offset += 8;
  instructionData.writeBigUInt64LE(BigInt(numOrders), offset);
  offset += 8;
  instructionData.writeBigUInt64LE(BigInt(cycleFrequency), offset);
  offset += 8;

  const createDcaOrderInstruction = new TransactionInstruction({
    programId: JUPITER_DCA_PROGRAM_ID,
    keys: [
