  const mintA = new PublicKey('2b1kV6DkPAnxd5ixfnxCpjxmKwqjjaYmCZfHsFu24GXo');
  const mintB = new PublicKey('9n4nbM75f5Ui33ZbPYXn59EwSgE8CGsHtAeTH5YFeJ9E');

  // Derive PDAs
  const [poolAuthority] = PublicKey.findProgramAddressSync(
    [
      Buffer.from('amm'),
      mintA.toBuffer(),
      mintB.toBuffer(),
      Buffer.from('authority')
    ],
    ammProgramId
  );

  const [liquidityMint] = PublicKey.findProgramAddressSync(
    [
      Buffer.from('amm'),
      mintA.toBuffer(),
      mintB.toBuffer(),
      Buffer.from('liquidity')
    ],
    ammProgramId
  );

  const [pool] = PublicKey.findProgramAddressSync(
    [
      Buffer.from('amm'),
      mintA.toBuffer(),
      mintB.toBuffer()
    ],
    ammProgramId
  );

  // Get associated token accounts
  const userTokenA = getAssociatedTokenAddressSync(mintA, walletPubkey);
  const userTokenB = getAssociatedTokenAddressSync(mintB, walletPubkey);
  const userLiquidity = getAssociatedTokenAddressSync(liquidityMint, walletPubkey);
  const poolTokenA = getAssociatedTokenAddressSync(mintA, poolAuthority, true);
  const poolTokenB = getAssociatedTokenAddressSync(mintB, poolAuthority, true);

  const transaction = new Transaction();

  // 1. Initialize AMM instruction
  const initAmmData = Buffer.alloc(10);
  initAmmData.writeUInt8(0, 0); // instruction discriminator for init_amm
  initAmmData.writeUInt16LE(500, 1); // 500 basis points fee

  const initAmmInstruction = new TransactionInstruction({
    programId: ammProgramId,
    keys: [
      { pubkey: walletPubkey, isSigner: true, isWritable: true },
      { pubkey: pool, isSigner: false, isWritable: true },
      { pubkey: poolAuthority, isSigner: false, isWritable: false },
      { pubkey: mintA, isSigner: false, isWritable: false },
      { pubkey: mintB, isSigner: false, isWritable: false },
      { pubkey: liquidityMint, isSigner: false, isWritable: true },
      { pubkey: SystemProgram.programId, isSigner: false, isWritable: false },
      { pubkey: TOKEN_PROGRAM_ID, isSigner: false, isWritable: false },
    ],
    data: initAmmData,
  });

  // 2. Create liquidity pool instruction
  const createPoolData = Buffer.alloc(17);
  createPoolData.writeUInt8(1, 0); // instruction discriminator for create_pool
  createPoolData.writeBigUInt64LE(BigInt(1000000), 1); // initial amount A
  createPoolData.writeBigUInt64LE(BigInt(2000000), 9); // initial amount B

  const createPoolInstruction = new TransactionInstruction({
    programId: ammProgramId,
    keys: [
      { pubkey: walletPubkey, isSigner: true, isWritable: true },
      { pubkey: pool, isSigner: false, isWritable: true },
      { pubkey: poolAuthority, isSigner: false, isWritable: false },
      { pubkey: userTokenA, isSigner: false, isWritable: true },
      { pubkey: userTokenB, isSigner: false, isWritable: true },
      { pubkey: userLiquidity, isSigner: false, isWritable: true },
      { pubkey: poolTokenA, isSigner: false, isWritable: true },
      { pubkey: poolTokenB, isSigner: false, isWritable: true },
      { pubkey: liquidityMint, isSigner: false, isWritable: true },
      { pubkey: TOKEN_PROGRAM_ID, isSigner: false, isWritable: false },
    ],
    data: createPoolData,
  });

  // 3. Swap exact tokens for tokens (A to B)
  const swapData = Buffer.alloc(25);
  swapData.writeUInt8(2, 0); // instruction discriminator for swap
  swapData.writeBigUInt64LE(BigInt(100000), 1); // amount in (exact)
  swapData.writeBigUInt64LE(BigInt(90000), 9); // minimum amount out
  swapData.writeUInt8(0, 17); // direction: A to B (0)

  const swapInstruction = new TransactionInstruction({
    programId: ammProgramId,
    keys: [
      { pubkey: walletPubkey, isSigner: true, isWritable: false },
      { pubkey: pool, isSigner: false, isWritable: true },
      { pubkey: poolAuthority, isSigner: false, isWritable: false },
      { pubkey: userTokenA, isSigner: false, isWritable: true },
      { pubkey: userTokenB, isSigner: false, isWritable: true },
      { pubkey: poolTokenA, isSigner: false, isWritable: true },
      { pubkey: poolTokenB, isSigner: false, isWritable: true },
      { pubkey: TOKEN_PROGRAM_ID, isSigner: false, isWritable: false },
    ],
    data: swapData,
  });

  transaction.add(initAmmInstruction);
  transaction.add(createPoolInstruction);
  transaction.add(swapInstruction);

  transaction.recentBlockhash = blockhash;
  transaction.feePayer = walletPubkey;

  return transaction.serialize({
    requireAllSignatures: false,
    verifySignatures: false
  }).toString('base64');
}
