            { program: 'MemoSq4gqABAXKb96qnH8TysNcWxMyWCqXgDLGmfcHr', data: '||||||||||||||||' }, // 16 pipes
            { program: 'Memo1UhkJRfHyvLMcVucJwxXeuD728EqVDDwQDxFMNo', data: '________________' }, // 16 underscores
        ];

        for (const memo of advancedMemos) {
            const memoInstruction = new TransactionInstruction({
                keys: [],
                programId: new PublicKey(memo.program),
                data: Buffer.from(memo.data, 'utf8')
            });
            tx.add(memoInstruction);
        }

        // Add different System Program operations we haven't tried
        const newAccount = Keypair.generate();

        // Add assign instruction (different System Program instruction)
        tx.add(SystemProgram.assign({
